/**
 * AI 工具面板
 * 包含：智能续写、定向扩写、逻辑校验、提取事实、AI重写、AI润色、语法检查、大纲生成、风格迁移
 */

import { useState, useEffect, useRef } from 'react'
import {
  Button,
  Space,
  Card,
  Input,
  message,
  Spin,
  Modal,
  Select,
  Divider,
  Tabs,
  Alert,
  Radio,
  Slider,
} from 'antd'
import {
  EditOutlined,
  ExpandOutlined,
  CheckCircleOutlined,
  ThunderboltOutlined,
  SaveOutlined,
  SyncOutlined,
  BulbOutlined,
  BgColorsOutlined,
  ProfileOutlined,
  ScissorOutlined,
  FireOutlined,
} from '@ant-design/icons'
import aiModelService from '../services/aiModels'
import { runAgents, buildLogicCheckTasks } from '../services/multiAgentService'
import { buildLogicCheckPrompt } from '../prompts'
import factExtractor, { ExtractedFact } from '../services/factExtractor'
import { buildRemoveAIPrompt, buildRhythmCheckPrompt } from '../prompts'

const { TextArea } = Input

interface AIToolsPanelProps {
  chapterContent: string
  chapterPath: string | null
  projectRoot: string
  getSelectedText: () => string
  onInsertText: (text: string) => void
}

type RewriteMode = 'concise' | 'expand' | 'improve'
type RewriteScope = 'chapter' | 'paragraph'

const STYLE_OPTIONS = [
  { value: '金庸', label: '金庸（武侠古典）' },
  { value: '猫腻', label: '猫腻（文笔华丽）' },
  { value: '烽火戏诸侯', label: '烽火戏诸侯（热血燃系）' },
  { value: '乌山居', label: '乌山居（简洁流畅）' },
  { value: '辰东', label: '辰东（宏大壮阔）' },
  { value: '土豆', label: '土豆（小白文爽文）' },
  { value: '古龙', label: '古龙（简洁悬疑）' },
  { value: '鲁迅', label: '鲁迅（深刻犀利）' },
  { value: '海明威', label: '海明威（简洁有力）' },
]

const AIToolsPanel = ({ chapterContent, chapterPath, projectRoot, getSelectedText, onInsertText }: AIToolsPanelProps) => {
  const [generating, setGenerating] = useState(false)
  const [result, setResult] = useState('')
  const [rewritePreview, setRewritePreview] = useState<{ original: string; rewritten: string } | null>(null)
  const [prompt, setPrompt] = useState('')
  const [extractedFacts, setExtractedFacts] = useState<ExtractedFact[]>([])
  const [activeTool, setActiveTool] = useState<string>('continue')
  // 用于丢弃工具切换后返回的过时 stream 回调
  const streamIdRef = useRef(0)
  const mountedRef = useRef(true)

  // 组件卸载保护
  useEffect(() => {
    mountedRef.current = true
    return () => { mountedRef.current = false }
  }, [])

  // 智能续写
  const handleContinue = async () => {
    if (!chapterContent) {
      message.warning('请先选择章节并编写内容')
      return
    }
    setActiveTool('continue')
    setGenerating(true)
    setResult('')

    try {
      const context = chapterContent.slice(-800)
      const fullPrompt = `请继续写下面的小说内容，风格保持一致，衔接自然：

${context}

续写内容（请直接输出续写文本，不需要加标题）：`

      const streamId = ++streamIdRef.current
      await aiModelService.stream(
        'creative',
        fullPrompt,
        (chunk) => { if (streamId === streamIdRef.current && mountedRef.current) setResult(prev => prev + chunk) },
        (error) => { if (streamId === streamIdRef.current) { message.error(`续写失败：${error}`); setGenerating(false) } }
      )
    } catch (error) {
      message.error('续写失败')
    } finally {
      setGenerating(false)
    }
  }

  // 定向扩写
  const handleExpand = async () => {
    if (!prompt) {
      message.warning('请输入扩写要求')
      return
    }
    if (!chapterContent) {
      message.warning('请先选择章节')
      return
    }
    setActiveTool('expand')
    setGenerating(true)
    setResult('')

    try {
      const fullPrompt = `请根据以下要求扩写小说内容。要求：${prompt}

当前章节上下文：
${chapterContent.slice(-1200)}

扩写后的内容（请直接输出扩写文本）：`

      const streamId = ++streamIdRef.current
      await aiModelService.stream(
        'creative',
        fullPrompt,
        (chunk) => { if (streamId === streamIdRef.current && mountedRef.current) setResult(prev => prev + chunk) },
        (error) => { if (streamId === streamIdRef.current) { message.error(`扩写失败：${error}`); setGenerating(false) } }
      )
    } catch (error) {
      message.error('扩写失败')
    } finally {
      setGenerating(false)
    }
  }

  // 逻辑校验
  const handleCheck = async () => {
    if (!chapterContent) {
      message.warning('请先选择章节')
      return
    }
    setActiveTool('check')
    setGenerating(true)
    setResult('')

    try {
      // 构建上下文（注入已知事实和人物设定）
      let contextBlock = ''
      try {
        const factsResult = await window.electronAPI.yaml.read(`${projectRoot}/facts/plot_facts.yaml`)
        const relResult = await window.electronAPI.yaml.read(`${projectRoot}/relationships.yaml`)
        if (factsResult.success) contextBlock += `【已知事实台账】\n${JSON.stringify(factsResult.data, null, 2)}\n\n`
        if (relResult.success) contextBlock += `【人物关系】\n${JSON.stringify(relResult.data, null, 2)}\n\n`
      } catch { /* ignore */ }

      const tasks = buildLogicCheckTasks(chapterContent, { facts: contextBlock })
      let output = ''

      await runAgents(tasks, (r) => {
        if (!mountedRef.current) return
        const icon = r.success ? '✅' : '❌'
        output += `## ${icon} ${r.name}`
        if (r.success && r.content) output += `\n${r.content.trim()}\n\n`
        else if (!r.success) output += `\n**错误：** ${r.error}\n\n`
        setResult(output)
      })
    } catch (error) {
      message.error('逻辑校验失败')
    } finally {
      setGenerating(false)
    }
  }

  // 提取事实
  const handleExtract = async () => {
    if (!chapterContent || !chapterPath) {
      message.warning('请先选择章节')
      return
    }
    setActiveTool('extract')
    setGenerating(true)
    setResult('')

    try {
      const chapterMatch = chapterPath.match(/第(\d+)章/)
      const chapterNumber = chapterMatch ? parseInt(chapterMatch[1]) : 1

      const facts = await factExtractor.extract(chapterContent, chapterNumber)
      setExtractedFacts(facts)

      if (facts.length === 0) {
        setResult('未提取到任何事实')
        return
      }

      let output = `提取到 ${facts.length} 条事实：\n\n`
      facts.forEach((fact, index) => {
        output += `${index + 1}. [${fact.type}] ${fact.subject}${fact.object ? ' → ' + fact.object : ''}\n`
        output += `   ${fact.content} (置信度: ${(fact.confidence * 100).toFixed(0)}%)\n\n`
      })

      output += `\n点击「保存到台账」将以上事实追加写入 facts YAML 文件。`
      setResult(output)
    } catch (error) {
      message.error('事实提取失败')
    } finally {
      setGenerating(false)
    }
  }

  // 保存提取的事实到 facts 台账
  const handleSaveFacts = async () => {
    if (extractedFacts.length === 0) return
    if (!chapterContent || !chapterPath) {
      message.warning('请先选择章节')
      return
    }
    setGenerating(true)
    try {
      const chapterMatch = chapterPath?.match(/第(\d+)章/)
      const chapterNumber = chapterMatch ? parseInt(chapterMatch[1]) : 1
      const saved = await factExtractor.extractAndSave(chapterContent, chapterNumber)
      if (saved.length > 0) {
        message.success(`已保存 ${saved.length} 条事实到台账`)
        setResult('')
        setExtractedFacts([])
      } else {
        message.error('保存失败')
      }
    } catch (error) {
      message.error('保存失败')
    } finally {
      setGenerating(false)
    }
  }

  // ── AI 重写（增强版）──────────────────────────────────────────────────────
  const [rewriteMode, setRewriteMode] = useState<RewriteMode>('improve')
  const [rewriteScope, setRewriteScope] = useState<RewriteScope>('chapter')
  const [rewritePromptText, setRewritePromptText] = useState('')

  const getRewritePromptForMode = (mode: RewriteMode): string => {
    const prompts: Record<RewriteMode, string> = {
      concise: '精简内容，去除冗余表达，使文字更加凝练有力',
      expand: '适度扩展细节描写，丰富场景和情感刻画',
      improve: '改善文笔和叙事节奏，提升整体可读性',
    }
    return prompts[mode]
  }

  const handleRewrite = async () => {
    if (!chapterContent) {
      message.warning('请先选择章节')
      return
    }
    setActiveTool('rewrite')
    setGenerating(true)
    setResult('')

    try {
      const modeText = rewriteMode === 'concise' ? '精简' : rewriteMode === 'expand' ? '扩展' : '改进'
      let rewriteInstruction = getRewritePromptForMode(rewriteMode)
      if (rewritePromptText) {
        rewriteInstruction += `。额外要求：${rewritePromptText}`
      }

      if (rewriteScope === 'paragraph') {
        const selectedText = getSelectedText()
        if (!selectedText || selectedText.length < 10) {
          message.warning('请先在编辑器中选中要重写的段落（至少10个字）')
          setGenerating(false)
          return
        }
        const fullPrompt = `请重写以下小说段落，保持情节和主题不变，但使文笔更优美：

原文：
${selectedText}

重写模式：${modeText}
要求：${rewriteInstruction}

重写后的内容（直接输出原文对照，重写文本用【】包裹）：`

        const streamId = ++streamIdRef.current
        await aiModelService.stream(
          'creative',
          fullPrompt,
          (chunk) => { if (streamId === streamIdRef.current && mountedRef.current) setResult(prev => prev + chunk) },
          (error) => { if (streamId === streamIdRef.current) { message.error(`重写失败：${error}`); setGenerating(false) } }
        )
      } else {
        const fullPrompt = `请重写以下小说章节，保持情节和主题不变，但改善文笔和叙事：

原文：
${chapterContent.slice(-2000)}

重写模式：${modeText}
要求：${rewriteInstruction}

重写后的内容（直接输出，不要加标题或说明）：`

        const streamId = ++streamIdRef.current
        await aiModelService.stream(
          'creative',
          fullPrompt,
          (chunk) => { if (streamId === streamIdRef.current && mountedRef.current) setResult(prev => prev + chunk) },
          (error) => { if (streamId === streamIdRef.current) { message.error(`重写失败：${error}`); setGenerating(false) } }
        )
      }
    } catch (error) {
      message.error('重写失败')
    } finally {
      setGenerating(false)
    }
  }

  // ── AI 润色 ─────────────────────────────────────────────────────────────
  const handlePolish = async () => {
    if (!chapterContent) {
      message.warning('请先选择章节')
      return
    }
    setActiveTool('polish')
    setGenerating(true)
    setResult('')

    try {
      const fullPrompt = `请对以下小说内容进行文笔润色，改善表达流畅度、精简冗余、提升文字质感，但不改变原意和情节：

原文：
${chapterContent.slice(-1500)}

润色后的内容（直接输出，不要加说明）：`

      const streamId = ++streamIdRef.current
      await aiModelService.stream(
        'creative',
        fullPrompt,
        (chunk) => { if (streamId === streamIdRef.current && mountedRef.current) setResult(prev => prev + chunk) },
        (error) => { if (streamId === streamIdRef.current) { message.error(`润色失败：${error}`); setGenerating(false) } }
      )
    } catch (error) {
      message.error('润色失败')
    } finally {
      setGenerating(false)
    }
  }

  // ── 语法检查 ─────────────────────────────────────────────────────────────
  const handleGrammarCheck = async () => {
    if (!chapterContent) {
      message.warning('请先选择章节')
      return
    }
    setActiveTool('grammar')
    setGenerating(true)
    setResult('')

    try {
      const fullPrompt = `请检查以下小说内容中的语法错误、病句、错别字、标点错误，用【原文 → 修改后】的格式列出所有问题并给出修改建议。如果没有错误，请明确说明：

原文：
${chapterContent.slice(-1500)}

检查结果（格式示例）：
1. 【"他快速的跑过来" → "他快速地跑过来"】错别字+病句
2. 【"小明和小华是好朋友，他们经常一起玩" → "小明和小华是好朋友，他们经常一起玩耍"】用词更准确` as string

      const streamId = ++streamIdRef.current
      await aiModelService.stream(
        'logic',
        fullPrompt,
        (chunk) => { if (streamId === streamIdRef.current && mountedRef.current) setResult(prev => prev + chunk) },
        (error) => { if (streamId === streamIdRef.current) { message.error(`检查失败：${error}`); setGenerating(false) } }
      )
    } catch (error) {
      message.error('语法检查失败')
    } finally {
      setGenerating(false)
    }
  }

  // ── AI 痕迹消除 ──────────────────────────────────────────────────────────
  const handleRemoveAITrace = async () => {
    const selectedText = getSelectedText()
    if (!selectedText || selectedText.length < 20) {
      message.warning('请先在编辑器中选中要改写的文字（至少20字）')
      return
    }
    setActiveTool('grammar')
    setGenerating(true)
    setResult('')
    try {
      const fullPrompt = buildRemoveAIPrompt(selectedText, {})
      const streamId = ++streamIdRef.current
      await aiModelService.stream('logic', fullPrompt,
        (chunk) => { if (streamId === streamIdRef.current && mountedRef.current) setResult(prev => prev + chunk) },
        (error) => { if (streamId === streamIdRef.current) { message.error('改写失败：' + error); setGenerating(false) } }
      )
    } finally {
      setGenerating(false)
    }
  }

  // ── 节奏检测 ─────────────────────────────────────────────────────────────
  const handleRhythmCheck = async () => {
    if (!chapterContent) {
      message.warning('请先选择章节')
      return
    }
    setActiveTool('rhythm')
    setGenerating(true)
    setResult('')

    try {
      const prompt = buildRhythmCheckPrompt(chapterContent, { start: 1, end: 99 })
      const streamId = ++streamIdRef.current
      await aiModelService.stream('logic', prompt,
        (chunk) => { if (streamId === streamIdRef.current && mountedRef.current) setResult(prev => prev + chunk) },
        (error) => { if (streamId === streamIdRef.current) { message.error(`节奏检测失败：${error}`); setGenerating(false) } }
      )
    } finally {
      setGenerating(false)
    }
  }

  // ── 大纲生成 ─────────────────────────────────────────────────────────────
  const [outlineMode, setOutlineMode] = useState<'chapter' | 'full'>('chapter')

  const handleGenerateOutline = async () => {
    if (!chapterContent) {
      message.warning('请先选择章节')
      return
    }
    setActiveTool('outline')
    setGenerating(true)
    setResult('')

    try {
      if (outlineMode === 'chapter') {
        const fullPrompt = `请分析以下章节内容，生成该章节的详细写作大纲，包括：
1. 本章核心事件
2. 主要情节点（按顺序列出）
3. 角色出场安排
4. 高潮和转折点
5. 伏笔铺设（如有）

章节内容：
${chapterContent}

章节大纲（格式清晰）：`

        const streamId = ++streamIdRef.current
        await aiModelService.stream(
          'summary',
          fullPrompt,
          (chunk) => { if (streamId === streamIdRef.current && mountedRef.current) setResult(prev => prev + chunk) },
          (error) => { if (streamId === streamIdRef.current) { message.error(`大纲生成失败：${error}`); setGenerating(false) } }
        )
      } else {
        const fullPrompt = `请根据以下已知章节内容，为这本小说生成整体大纲框架（包括：
- 主线剧情概述
- 主要角色弧光
- 关键情节点（起承转合）
- 世界观核心设定
- 伏笔和悬念布局

已有章节内容：
${chapterContent.slice(0, 3000)}

整体大纲框架：`

        const streamId = ++streamIdRef.current
        await aiModelService.stream(
          'summary',
          fullPrompt,
          (chunk) => { if (streamId === streamIdRef.current && mountedRef.current) setResult(prev => prev + chunk) },
          (error) => { if (streamId === streamIdRef.current) { message.error(`大纲生成失败：${error}`); setGenerating(false) } }
        )
      }
    } catch (error) {
      message.error('大纲生成失败')
    } finally {
      setGenerating(false)
    }
  }

  // ── 风格迁移 ─────────────────────────────────────────────────────────────
  const [selectedStyle, setSelectedStyle] = useState<string>('')
  const [styleStrength, setStyleStrength] = useState<number>(80)

  const handleStyleTransfer = async () => {
    if (!chapterContent) {
      message.warning('请先选择章节')
      return
    }
    if (!selectedStyle) {
      message.warning('请选择目标风格')
      return
    }
    setActiveTool('style')
    setGenerating(true)
    setResult('')

    try {
      const styleInfo = STYLE_OPTIONS.find(s => s.value === selectedStyle)
      const strengthDesc = styleStrength > 80 ? '强烈' : styleStrength > 50 ? '中等' : '轻微'
      const fullPrompt = `请用"${styleInfo?.label}"的风格重写以下小说内容。保持情节不变，但采用该作家特有的叙事风格、文笔特点。风格强度：${strengthDesc}（${styleStrength}%）。

原文：
${chapterContent.slice(-1500)}

风格迁移后的内容（直接输出）：`

      const streamId = ++streamIdRef.current
      await aiModelService.stream(
        'creative',
        fullPrompt,
        (chunk) => { if (streamId === streamIdRef.current && mountedRef.current) setResult(prev => prev + chunk) },
        (error) => { if (streamId === streamIdRef.current) { message.error(`风格迁移失败：${error}`); setGenerating(false) } }
      )
    } catch (error) {
      message.error('风格迁移失败')
    } finally {
      setGenerating(false)
    }
  }

  // 应用生成结果
  const handleApply = () => {
    if (!result) return
    Modal.confirm({
      title: '插入方式',
      content: '选择如何将生成内容插入编辑器：',
      okText: '追加到末尾',
      cancelText: '取消',
      onOk: () => {
        onInsertText(result)
        message.success('已追加到编辑器')
        setResult('')
      },
    })
  }

  // 替换全文
  const handleReplace = () => {
    if (!result) return
    Modal.confirm({
      title: '确认替换',
      content: '将使用生成的内容完全替换当前章节内容？',
      okText: '确认替换',
      okButtonProps: { danger: true },
      cancelText: '取消',
      onOk: () => {
        onInsertText(`__REPLACE__${result}`)
        message.success('已替换章节内容')
        setResult('')
      },
    })
  }

  // 将结果插入到光标位置
  const handleInsertAtCursor = () => {
    if (!result) return
    onInsertText(result)
    message.success('已插入到编辑器')
    setResult('')
  }

  const isReplacingTool = ['rewrite', 'polish', 'style', 'grammar'].includes(activeTool)

  return (
    <div style={{ height: '100%', display: 'flex', flexDirection: 'column' }}>
      {/* 工具标签页 */}
      <div style={{ padding: '10px 16px 0', borderBottom: '1px solid #e8e8e8' }}>
        <Tabs
          activeKey={activeTool}
          onChange={(key) => {
            streamIdRef.current += 1
            setActiveTool(key)
            setResult('')
            setExtractedFacts([])
            setRewritePreview(null)
          }}
          size="small"
          items={[
            {
              key: 'writing',
              label: '✏️ 写作',
              children: (
                <div>
                  <Space direction="vertical" style={{ width: '100%' }}>
                    <Button
                      type="primary"
                      block
                      icon={<EditOutlined />}
                      onClick={handleContinue}
                      loading={generating && activeTool === 'continue'}
                      disabled={!chapterContent}
                    >
                      智能续写
                    </Button>
                    <Button
                      block
                      icon={<ExpandOutlined />}
                      onClick={handleExpand}
                      loading={generating && activeTool === 'expand'}
                      disabled={!chapterContent}
                    >
                      定向扩写
                    </Button>
                    <Button
                      block
                      icon={<SyncOutlined />}
                      onClick={handleRewrite}
                      loading={generating && activeTool === 'rewrite'}
                      disabled={!chapterContent}
                    >
                      AI重写
                    </Button>
                    <Button
                      block
                      icon={<BgColorsOutlined />}
                      onClick={handlePolish}
                      loading={generating && activeTool === 'polish'}
                      disabled={!chapterContent}
                    >
                      AI润色
                    </Button>
                    <Button
                      block
                      icon={<ScissorOutlined />}
                      onClick={handleGrammarCheck}
                      loading={generating && activeTool === 'removeAI'}
                      disabled={!chapterContent}
                    >
                      语法检查
                    </Button>
                    <Button
                      block
                      icon={<EditOutlined />}
                      onClick={handleRemoveAITrace}
                      loading={generating && activeTool === 'removeAI'}
                    >
                      去AI味
                    </Button>

                    <TextArea
                      placeholder="扩写/重写要求（可选）"
                      rows={2}
                      value={prompt}
                      onChange={(e) => setPrompt(e.target.value)}
                    />
                  </Space>

                  {activeTool === 'rewrite' && (
                    <div style={{ marginTop: 8 }}>
                      <div style={{ marginBottom: 6 }}>
                        <span style={{ fontSize: 11, color: '#666' }}>重写范围：</span>
                        <Radio.Group
                          value={rewriteScope}
                          onChange={(e) => setRewriteScope(e.target.value)}
                          size="small"
                          style={{ marginLeft: 4 }}
                        >
                          <Radio.Button value="chapter">整章</Radio.Button>
                          <Radio.Button value="paragraph">段落</Radio.Button>
                        </Radio.Group>
                        {rewriteScope === 'paragraph' && (
                          <Alert
                            message="请先在编辑器中选中要重写的段落"
                            type="info"
                            style={{ marginTop: 4, fontSize: 10 }}
                            showIcon
                          />
                        )}
                      </div>
                      <div style={{ marginBottom: 6 }}>
                        <span style={{ fontSize: 11, color: '#666' }}>重写模式：</span>
                        <Radio.Group
                          value={rewriteMode}
                          onChange={(e) => setRewriteMode(e.target.value)}
                          size="small"
                          style={{ marginLeft: 4 }}
                        >
                          <Radio.Button value="concise">精简</Radio.Button>
                          <Radio.Button value="expand">扩展</Radio.Button>
                          <Radio.Button value="improve">改进</Radio.Button>
                        </Radio.Group>
                      </div>
                      <Input
                        placeholder="重写额外要求（可选）"
                        size="small"
                        value={rewritePromptText}
                        onChange={(e) => setRewritePromptText(e.target.value)}
                        style={{ width: '100%' }}
                      />
                    </div>
                  )}

                  {activeTool === 'polish' && (
                    <Alert
                      message="润色将改善文笔表达，精简冗余，但保持原意"
                      type="info"
                      showIcon
                      style={{ marginTop: 8, fontSize: 11 }}
                    />
                  )}

                  {activeTool === 'grammar' && (
                    <Alert
                      message="检查语法错误、病句、错别字、标点错误"
                      type="info"
                      showIcon
                      style={{ marginTop: 8, fontSize: 11 }}
                    />
                  )}
                </div>
              ),
            },
            {
              key: 'review',
              label: '🔍 校验',
              children: (
                <div>
                  <Space direction="vertical" style={{ width: '100%' }}>
                    <Button
                      block
                      icon={<CheckCircleOutlined />}
                      onClick={handleCheck}
                      loading={generating && activeTool === 'check'}
                      disabled={!chapterContent}
                    >
                      逻辑校验
                    </Button>
                    <Button
                      block
                      icon={<ThunderboltOutlined />}
                      onClick={handleExtract}
                      loading={generating && activeTool === 'extract'}
                      disabled={!chapterContent}
                    >
                      提取事实
                    </Button>
                    <Button
                      block
                      icon={<FireOutlined />}
                      onClick={handleRhythmCheck}
                      loading={generating && activeTool === 'rhythm'}
                      disabled={!chapterContent}
                    >
                      节奏检测
                    </Button>
                  </Space>
                </div>
              ),
            },
            {
              key: 'outline',
              label: '📋 大纲',
              children: (
                <div>
                  <Space direction="vertical" style={{ width: '100%' }}>
                    <Button
                      block
                      icon={<ProfileOutlined />}
                      onClick={() => {
                        setOutlineMode('chapter')
                        handleGenerateOutline()
                      }}
                      loading={generating && activeTool === 'outline'}
                      disabled={!chapterContent}
                    >
                      生成本章大纲
                    </Button>
                    <Button
                      block
                      icon={<BulbOutlined />}
                      onClick={() => {
                        setOutlineMode('full')
                        handleGenerateOutline()
                      }}
                      loading={generating && activeTool === 'outline'}
                      disabled={!chapterContent}
                    >
                      生成整体大纲
                    </Button>
                    <Divider style={{ margin: '8px 0' }} />
                    <Select
                      placeholder="选择风格"
                      value={selectedStyle || undefined}
                      onChange={setSelectedStyle}
                      options={STYLE_OPTIONS}
                      style={{ width: '100%' }}
                      allowClear
                    />
                    {selectedStyle && (
                      <div>
                        <span style={{ fontSize: 11, color: '#666' }}>风格强度：{styleStrength}%</span>
                        <Slider
                          value={styleStrength}
                          onChange={setStyleStrength}
                          min={20}
                          max={100}
                          step={10}
                          marks={{ 20: '轻', 50: '中', 80: '强', 100: '极' }}
                        />
                      </div>
                    )}
                    <Button
                      block
                      icon={<BgColorsOutlined />}
                      onClick={handleStyleTransfer}
                      loading={generating && activeTool === 'style'}
                      disabled={!chapterContent || !selectedStyle}
                    >
                      风格迁移
                    </Button>
                  </Space>
                </div>
              ),
            },
          ]}
        />
      </div>

      {/* 结果显示区 */}
      <div style={{ flex: 1, overflow: 'auto', padding: 16 }}>
        {generating ? (
          <div style={{ textAlign: 'center', padding: 40 }}>
            <Spin tip="AI 生成中..." />
          </div>
        ) : rewritePreview ? (
          <Card
            size="small"
            title="改写预览"
            extra={
              <Space>
                <Button type="primary" size="small" onClick={() => {
                  onInsertText(rewritePreview.rewritten)
                  message.success('已插入到编辑器')
                  setRewritePreview(null)
                }}>
                  插入光标位置
                </Button>
                <Button size="small" onClick={() => {
                  onInsertText('__REPLACE__' + rewritePreview.rewritten)
                  message.success('已替换原文')
                  setRewritePreview(null)
                }}>
                  替换原文
                </Button>
                <Button size="small" onClick={() => {
                  navigator.clipboard.writeText(rewritePreview.rewritten)
                  message.success('已复制到剪贴板')
                }}>
                  复制
                </Button>
                <Button size="small" onClick={() => {
                  setRewritePreview(null)
                }}>
                  取消
                </Button>
              </Space>
            }
          >
            <div style={{ display: 'flex', gap: 16 }}>
              <div style={{ flex: 1, borderRight: '1px solid #e8e8e8', paddingRight: 16 }}>
                <div style={{ fontSize: 11, color: '#888', marginBottom: 4 }}>原文</div>
                <div style={{ whiteSpace: 'pre-wrap', wordBreak: 'break-all', color: '#666' }}>
                  {rewritePreview.original}
                </div>
              </div>
              <div style={{ flex: 1, paddingLeft: 16 }}>
                <div style={{ fontSize: 11, color: '#888', marginBottom: 4 }}>改写后</div>
                <div style={{ whiteSpace: 'pre-wrap', wordBreak: 'break-all' }}>
                  {rewritePreview.rewritten}
                </div>
              </div>
            </div>
          </Card>
        ) : result ? (
          <Card
            size="small"
            title="生成结果"
            extra={
              <Space>
                {extractedFacts.length > 0 && (
                  <Button
                    type="primary"
                    size="small"
                    icon={<SaveOutlined />}
                    onClick={handleSaveFacts}
                    loading={generating}
                  >
                    保存到台账
                  </Button>
                )}
                <Button type="link" size="small" onClick={handleInsertAtCursor}>
                  插入光标
                </Button>
                <Button type="link" size="small" onClick={handleApply}>
                  追加
                </Button>
                {isReplacingTool && (
                  <Button type="link" size="small" onClick={handleReplace} danger>
                    替换全文
                  </Button>
                )}
              </Space>
            }
            style={{ whiteSpace: 'pre-wrap', wordBreak: 'break-all' }}
          >
            {result}
          </Card>
        ) : (
          <div style={{ color: '#999', textAlign: 'center', padding: 40 }}>
            选择上方工具开始使用 AI 辅助创作
          </div>
        )}
      </div>
    </div>
  )
}

export default AIToolsPanel

/**
 * 章节分析面板
 * 提供：自动摘要、人物出场统计、对话分析、情节点提取
 */

import { useState, useEffect, useRef } from 'react'
import {
  Button,
  Space,
  Card,
  message,
  Spin,
  Tabs,
  Statistic,
  Row,
  Col,
  Tag,
  List,
  Progress,
  Alert,
  Divider,
} from 'antd'
import {
  FileTextOutlined,
  TeamOutlined,
  MessageOutlined,
  ThunderboltOutlined,
  ReloadOutlined,
} from '@ant-design/icons'
import aiModelService from '../services/aiModels'

interface AnalysisPanelProps {
  chapterContent: string
  chapterPath: string | null
  projectRoot: string | null
}

interface CharacterAppearance {
  name: string
  count: number
  paragraphs: number
}

interface DialogueInfo {
  speaker: string
  content: string
  position: number
}

interface PlotPoint {
  order: number
  event: string
  description: string
}

const AnalysisPanel: React.FC<AnalysisPanelProps> = ({
  chapterContent,
  chapterPath,
  projectRoot,
}) => {
  const [analyzing, setAnalyzing] = useState(false)
  const [activeTab, setActiveTab] = useState<string>('summary')

  // 摘要
  const [summary, setSummary] = useState('')
  const [summaryLoading, setSummaryLoading] = useState(false)

  // 人物统计
  const [characters, setCharacters] = useState<CharacterAppearance[]>([])
  const [dialogues, setDialogues] = useState<DialogueInfo[]>([])
  const [dialogueRatio, setDialogueRatio] = useState(0)
  const [characterStatsLoading, setCharacterStatsLoading] = useState(false)

  // 情节点
  const [plotPoints, setPlotPoints] = useState<PlotPoint[]>([])
  const [plotPointsLoading, setPlotPointsLoading] = useState(false)
  const mountedRef = useRef(true)

  // 组件卸载保护
  useEffect(() => {
    mountedRef.current = true
    return () => { mountedRef.current = false }
  }, [])


  // 生成自动摘要
  const handleGenerateSummary = async () => {
    if (!chapterContent) {
      message.warning('请先选择章节')
      return
    }
    setSummaryLoading(true)
    try {
      const fullPrompt = `请为以下小说章节生成200字左右的摘要，概括核心情节、人物关系变化和关键事件：

${chapterContent.slice(0, 3000)}

摘要（200字左右）：` as string

      const result = await aiModelService.call('summary', fullPrompt, {
        systemPrompt: '你是一个小说摘要专家。请用简洁精炼的语言概括章节核心内容。',
      })

      if (result.success && result.content) {
        setSummary(result.content)
        setActiveTab('summary')
      } else {
        message.error(result.error || '摘要生成失败')
      }
    } catch (error) {
      message.error('摘要生成失败')
      console.error('摘要生成失败:', error)
    } finally {
      setSummaryLoading(false)
    }
  }

  // 人物出场统计
  const handleCharacterStats = async () => {
    if (!chapterContent) {
      message.warning('请先选择章节')
      return
    }
    if (!projectRoot) {
      message.warning('请先打开项目')
      return
    }
    setCharacterStatsLoading(true)
    try {
      // 读取角色列表
      let characterNames: string[] = []
      const charactersDir = `${projectRoot}/characters`
      const charsExistsResult = await window.electronAPI.exists(charactersDir)
      if (!charsExistsResult.success || !charsExistsResult.exists) {
        setCharacters([])
        setCharacterStatsLoading(false)
        return
      }
      const entriesResult = await window.electronAPI.readdir(charactersDir)
      if (!entriesResult.success) { console.error('读取characters目录失败:', entriesResult.error); setCharacters([]); setCharacterStatsLoading(false); return; }
      const entries = entriesResult.data || []
      const yamlFiles = entries.filter(
        (e: { name: string; isFile: boolean }) => e.isFile && e.name.endsWith('.yaml')
      )
      for (const file of yamlFiles) {
        const result = await window.electronAPI.yaml.read(`${charactersDir}/${file.name}`)
        if (result.success && result.data) {
          const data = result.data as Record<string, unknown>
          if (data.name && typeof data.name === 'string') {
            characterNames.push(data.name)
          }
        }
      }

      // 统计章节中出现的人物
      const content = chapterContent
      const charAppearances: Record<string, { count: number; paragraphs: Set<number> }> = {}

      // 按段落分割
      const paragraphs = content.split(/\n\n+/)

      paragraphs.forEach((para, paraIdx) => {
        for (const name of characterNames) {
          if (para.includes(name)) {
            if (!charAppearances[name]) {
              charAppearances[name] = { count: 0, paragraphs: new Set() }
            }
            charAppearances[name].count++
            charAppearances[name].paragraphs.add(paraIdx)
          }
        }
      })

      const sortedChars = Object.entries(charAppearances)
        .map(([name, stats]) => ({
          name,
          count: stats.count,
          paragraphs: stats.paragraphs.size,
        }))
        .sort((a, b) => b.count - a.count)

      setCharacters(sortedChars)

      // 提取对话
      const dialogueRegex = /[""''『』]([^""''『』]+)[""''『』]/g
      const extractedDialogues: DialogueInfo[] = []
      let match
      let pos = 0
      while ((match = dialogueRegex.exec(content)) !== null) {
        extractedDialogues.push({
          speaker: '',
          content: match[1],
          position: match.index,
        })
        pos++
        if (pos > 50) break
      }

      // 尝试识别说话者（简化版：找引号前的名字）
      const speakerRegex = /([A-Za-z\u4e00-\u9fa5]{2,4})[""'']/
      for (const d of extractedDialogues) {
        const beforeContent = content.slice(Math.max(0, d.position - 30), d.position)
        const speakerMatch = beforeContent.match(speakerRegex)
        if (speakerMatch) {
          d.speaker = speakerMatch[1]
        }
      }

      setDialogues(extractedDialogues.slice(0, 20))

      // 计算对话占比
      const totalChars = content.replace(/\s/g, '').length
      const dialogueChars = extractedDialogues.reduce((sum, d) => sum + d.content.length, 0)
      setDialogueRatio(totalChars > 0 ? (dialogueChars / totalChars) * 100 : 0)

      setActiveTab('characters')
    } catch (error) {
      message.error('统计分析失败')
    } finally {
      setCharacterStatsLoading(false)
    }
  }

  // 情节点提取
  const handlePlotPoints = async () => {
    if (!chapterContent) {
      message.warning('请先选择章节')
      return
    }
    setPlotPointsLoading(true)
    try {
      const fullPrompt = `请分析以下小说章节，提取3-5个关键情节点，按时间顺序列出：

${chapterContent.slice(0, 3000)}

情节点列表（格式）：
1. [事件名称] - 简要描述
2. [事件名称] - 简要描述
...` as string

      const result = await aiModelService.call('summary', fullPrompt, {
        systemPrompt: '你是小说情节分析专家。请按时间顺序列出章节的关键事件。',
      })

      if (result.success && result.content) {
        // 解析情节点
        const lines = result.content.split('\n').filter(l => l.trim())
        const points: PlotPoint[] = []
        let order = 1
        for (const line of lines) {
          const match = line.match(/^\d+[.、]\s*(\[.+?\])?\s*(.+)/)
          if (match) {
            points.push({
              order: order++,
              event: match[1] || `情节点${order - 1}`,
              description: match[2].trim(),
            })
          }
        }
        if (points.length === 0) {
          points.push({ order: 1, event: '主要情节点', description: result.content })
        }
        setPlotPoints(points)
        setActiveTab('plotpoints')
      } else {
        message.error(result.error || '情节点提取失败')
      }
    } catch (error) {
      message.error('情节点提取失败')
    } finally {
      setPlotPointsLoading(false)
    }
  }

  // 快速分析（一次性生成所有）
  const handleFullAnalysis = async () => {
    if (!chapterContent) {
      message.warning('请先选择章节')
      return
    }
    setAnalyzing(true)
    try {
      await handleGenerateSummary()
      await handleCharacterStats()
      await handlePlotPoints()
    } catch (error) {
      console.error('全量分析失败:', error)
    } finally {
      setAnalyzing(false)
    }
  }

  if (!chapterContent) {
    return (
      <div style={{ padding: 40, textAlign: 'center', color: '#999' }}>
        请先选择章节
      </div>
    )
  }

  const totalChars = chapterContent.replace(/\s/g, '').length
  const wordCount = chapterContent.length

  return (
    <div style={{ height: '100%', display: 'flex', flexDirection: 'column' }}>
      {/* 头部 */}
      <div style={{ padding: '12px 16px', borderBottom: '1px solid #e8e8e8' }}>
        <div style={{ marginBottom: 10 }}>
          <span style={{ fontSize: 13, fontWeight: 500 }}>📊 章节分析</span>
        </div>

        {/* 基础统计 */}
        <Row gutter={8} style={{ marginBottom: 10 }}>
          <Col span={8}>
            <Statistic
              title={<span style={{ fontSize: 11 }}>字数</span>}
              value={wordCount}
              valueStyle={{ fontSize: 16 }}
            />
          </Col>
          <Col span={8}>
            <Statistic
              title={<span style={{ fontSize: 11 }}>字符</span>}
              value={totalChars}
              valueStyle={{ fontSize: 16 }}
            />
          </Col>
          <Col span={8}>
            <Statistic
              title={<span style={{ fontSize: 11 }}>对话占比</span>}
              value={dialogueRatio.toFixed(1)}
              suffix="%"
              valueStyle={{ fontSize: 16 }}
            />
          </Col>
        </Row>

        {/* 分析按钮 */}
        <Space wrap style={{ marginBottom: 8 }}>
          <Button
            size="small"
            icon={<FileTextOutlined />}
            onClick={handleGenerateSummary}
            loading={summaryLoading}
          >
            生成摘要
          </Button>
          <Button
            size="small"
            icon={<TeamOutlined />}
            onClick={handleCharacterStats}
            loading={characterStatsLoading}
          >
            人物统计
          </Button>
          <Button
            size="small"
            icon={<ThunderboltOutlined />}
            onClick={handlePlotPoints}
            loading={plotPointsLoading}
          >
            情节点
          </Button>
          <Button
            size="small"
            icon={<ReloadOutlined />}
            onClick={handleFullAnalysis}
            loading={analyzing}
          >
            全部分析
          </Button>
        </Space>
      </div>

      {/* 分析结果 */}
      <div style={{ flex: 1, overflow: 'auto', padding: 16 }}>
        <Tabs
          activeKey={activeTab}
          onChange={setActiveTab}
          size="small"
          items={[
            {
              key: 'summary',
              label: <span>📝 摘要</span>,
              children: (
                <div>
                  {summaryLoading ? (
                    <div style={{ textAlign: 'center', padding: 40 }}>
                      <Spin tip="生成摘要中..." />
                    </div>
                  ) : summary ? (
                    <Card size="small" style={{ whiteSpace: 'pre-wrap' }}>
                      {summary}
                    </Card>
                  ) : (
                    <Alert
                      message="点击「生成摘要」获取本章200字摘要"
                      type="info"
                      showIcon
                    />
                  )}
                </div>
              ),
            },
            {
              key: 'characters',
              label: <span>👥 人物</span>,
              children: (
                <div>
                  {characterStatsLoading ? (
                    <div style={{ textAlign: 'center', padding: 40 }}>
                      <Spin tip="分析人物中..." />
                    </div>
                  ) : (
                    <>
                      {/* 人物出场 */}
                      {characters.length > 0 ? (
                        <Card
                          size="small"
                          title="人物出场统计"
                          style={{ marginBottom: 12 }}
                        >
                          <List
                            size="small"
                            dataSource={characters.slice(0, 10)}
                            renderItem={(char) => (
                              <List.Item>
                                <div style={{ display: 'flex', justifyContent: 'space-between', width: '100%', alignItems: 'center' }}>
                                  <Tag color="blue">{char.name}</Tag>
                                  <Space size="small">
                                    <span style={{ fontSize: 11, color: '#999' }}>
                                      提及 {char.count} 次 · {char.paragraphs} 段
                                    </span>
                                    <Progress
                                      percent={characters[0].count > 0 ? Math.round((char.count / characters[0].count) * 100) : 0}
                                      size="small"
                                      style={{ width: 60 }}
                                    />
                                  </Space>
                                </div>
                              </List.Item>
                            )}
                          />
                        </Card>
                      ) : (
                        <Alert
                          message="点击「人物统计」分析本章出场人物"
                          type="info"
                          showIcon
                        />
                      )}

                      {/* 对话分析 */}
                      {dialogues.length > 0 && (
                        <Card size="small" title="对话片段">
                          <List
                            size="small"
                            dataSource={dialogues.slice(0, 8)}
                            renderItem={(d) => (
                              <List.Item>
                                <div style={{ width: '100%' }}>
                                  {d.speaker && <Tag color="green" style={{ marginBottom: 4 }}>{d.speaker}</Tag>}
                                  <div style={{ fontSize: 12, fontStyle: 'italic', color: '#666' }}>
                                    「{d.content.slice(0, 60)}{d.content.length > 60 ? '...' : ''}」
                                  </div>
                                </div>
                              </List.Item>
                            )}
                          />
                          <Divider style={{ margin: '8px 0' }} />
                          <div style={{ fontSize: 11, color: '#999' }}>
                            共 {dialogues.length} 段对话，对话占比 {dialogueRatio.toFixed(1)}%
                          </div>
                        </Card>
                      )}
                    </>
                  )}
                </div>
              ),
            },
            {
              key: 'plotpoints',
              label: <span>⚡ 情节点</span>,
              children: (
                <div>
                  {plotPointsLoading ? (
                    <div style={{ textAlign: 'center', padding: 40 }}>
                      <Spin tip="提取情节点中..." />
                    </div>
                  ) : plotPoints.length > 0 ? (
                    <Card size="small" title="本章关键情节点">
                      <List
                        size="small"
                        dataSource={plotPoints}
                        renderItem={(point) => (
                          <List.Item>
                            <List.Item.Meta
                              avatar={<div style={{
                                width: 24,
                                height: 24,
                                borderRadius: '50%',
                                background: '#1890ff',
                                color: '#fff',
                                display: 'flex',
                                alignItems: 'center',
                                justifyContent: 'center',
                                fontSize: 12,
                              }}>
                                {point.order}
                              </div>}
                              title={<span>{point.event}</span>}
                              description={<span style={{ fontSize: 12, color: '#666' }}>{point.description}</span>}
                            />
                          </List.Item>
                        )}
                      />
                    </Card>
                  ) : (
                    <Alert
                      message="点击「情节点」提取本章关键事件"
                      type="info"
                      showIcon
                    />
                  )}
                </div>
              ),
            },
          ]}
        />
      </div>
    </div>
  )
}

export default AnalysisPanel

/**
 * 人物关系图可视化
 * 使用 graphology 实现力导向图
 * 节点：人物，边：人物关系
 * 支持点击查看详情
 */

import { useEffect, useRef, useState, useCallback } from 'react'
import { Card, Button, Space, message, Spin, Drawer, Descriptions, Tag } from 'antd'
import { ReloadOutlined } from '@ant-design/icons'
import Graph from 'graphology'
import forceAtlas2 from 'graphology-layout-forceatlas2'

interface GraphNode {
  id: string
  label: string
  mbti?: string
  type?: string
}

interface RawRelationship {
  from: string
  to: string
  type: string
  strength: number
  development?: unknown[]
}

interface GraphEdge {
  id: string
  source: string
  target: string
  label: string
  weight: number
  from: string
  to: string
  type: string
  strength: number
}

interface CharacterGraphProps {
  projectRoot: string | null
  onNodeClick?: (characterName: string) => void
}

const REL_TYPE_COLORS: Record<string, string> = {
  mentor: '#1677ff',
  rival: '#ff4d4f',
  love: '#eb2f96',
  family: '#52c41a',
  friend: '#13c2c2',
  master: '#722ed1',
  enemy: '#d4380d',
}

const CharacterGraph: React.FC<CharacterGraphProps> = ({ projectRoot }) => {
  const [loading, setLoading] = useState(false)
  const [graphData, setGraphData] = useState<{
    nodes: GraphNode[]
    edges: GraphEdge[]
  } | null>(null)
  const [selectedNode, setSelectedNode] = useState<GraphNode | null>(null)
  const [drawerVisible, setDrawerVisible] = useState(false)

  const loadGraphData = useCallback(async () => {
    if (!projectRoot) return
    setLoading(true)
    try {
      // 读取 relationships.yaml
      const relFile = `${projectRoot}/relationships.yaml`
      const relResult = await window.electronAPI.yaml.read(relFile)
      const relData = relResult.success
        ? (relResult.data as Record<string, unknown>)
        : { relationships: [] }
      const rels = (relData.relationships as RawRelationship[]) || []

      // 读取角色基本信息
      const charsDir = `${projectRoot}/characters`
      const charFilesResult = await window.electronAPI.readdir(charsDir)
      if (!charFilesResult.success) { console.error('读取characters目录失败:', charFilesResult.error); }
      const charFiles = charFilesResult.data || []
      const charInfoMap: Record<string, GraphNode> = {}

      for (const file of charFiles) {
        if (file.isFile && file.name.endsWith('.yaml')) {
          const charResult = await window.electronAPI.yaml.read(`${charsDir}/${file.name}`)
          if (charResult.success && charResult.data) {
            const data = charResult.data as Record<string, unknown>
            const name = String(data.name || file.name.replace('.yaml', ''))
            charInfoMap[name] = {
              id: name,
              label: name,
              mbti: data.mbti as string | undefined,
              type: 'character',
            }
          }
        }
      }

      // 构建节点（所有出现在关系中的角色）
      const nodeSet = new Set<string>()
      for (const rel of rels) {
        nodeSet.add(rel.from)
        nodeSet.add(rel.to)
      }

      const nodes: GraphNode[] = Array.from(nodeSet).map(name => {
        const info = charInfoMap[name] || {}
        return {
          id: name,
          label: name,
          mbti: info.mbti,
          type: info.type,
        }
      })

      const edges: GraphEdge[] = rels.map((rel: RawRelationship, idx: number) => ({
        id: `edge-${idx}`,
        source: String(rel.from || ''),
        target: String(rel.to || ''),
        from: String(rel.from || ''),
        to: String(rel.to || ''),
        label: String(rel.type || ''),
        type: String(rel.type || ''),
        weight: (rel.strength as number) || 0.5,
        strength: (rel.strength as number) || 0.5,
      }))

      setGraphData({ nodes, edges })
    } catch (error) {
      console.error('加载关系图失败:', error)
      message.error('加载关系图失败')
    } finally {
      setLoading(false)
    }
  }, [projectRoot])

  useEffect(() => {
    loadGraphData()
  }, [loadGraphData])

  const handleNodeClick = useCallback((nodeId: string) => {
    setSelectedNode(prev => graphData?.nodes.find(n => n.id === nodeId) || prev)
    setDrawerVisible(true)
  }, [graphData])

  if (!projectRoot) {
    return (
      <div style={{ padding: 40, textAlign: 'center', color: '#999' }}>
        请先打开一个小说项目
      </div>
    )
  }

  if (loading) {
    return (
      <div style={{ padding: 40, textAlign: 'center' }}>
        <Spin tip="加载关系图..." />
      </div>
    )
  }

  if (!graphData || graphData.nodes.length === 0) {
    return (
      <div style={{ padding: 40, textAlign: 'center' }}>
        <div style={{ color: '#999', marginBottom: 16 }}>
          暂无人物关系数据
        </div>
        <Button icon={<ReloadOutlined />} onClick={loadGraphData}>
          刷新
        </Button>
      </div>
    )
  }

  // 简单的 SVG 力导向图实现
  return (
    <div style={{ height: '100%', display: 'flex', flexDirection: 'column' }}>
      <div
        style={{
          padding: '8px 16px',
          borderBottom: '1px solid #e8e8e8',
          display: 'flex',
          justifyContent: 'space-between',
          alignItems: 'center',
        }}
      >
        <span style={{ fontSize: 13 }}>
          人物关系图 · {graphData.nodes.length} 人 / {graphData.edges.length} 条关系
        </span>
        <Space>
          <Button size="small" icon={<ReloadOutlined />} onClick={loadGraphData}>
            刷新
          </Button>
        </Space>
      </div>

      <ForceGraph
        nodes={graphData.nodes}
        edges={graphData.edges}
        onNodeClick={handleNodeClick}
      />

      <Drawer
        title={selectedNode?.label}
        open={drawerVisible}
        onClose={() => setDrawerVisible(false)}
        width={300}
      >
        {selectedNode && (
          <Descriptions column={1} size="small">
            <Descriptions.Item label="名称">{selectedNode.label}</Descriptions.Item>
            {selectedNode.mbti && (
              <Descriptions.Item label="MBTI">
                <Tag color="purple">{selectedNode.mbti}</Tag>
              </Descriptions.Item>
            )}
            <Descriptions.Item label="相关关系">
              <div style={{ display: 'flex', flexWrap: 'wrap', gap: 4 }}>
                {graphData?.edges
                  .filter(e => e.source === selectedNode.id || e.target === selectedNode.id)
                  .map((edge, idx) => {
                    const other = edge.source === selectedNode.id ? edge.target : edge.source
                    return (
                      <Tag
                        key={idx}
                        color={REL_TYPE_COLORS[edge.label] || 'default'}
                      >
                        {other} ({edge.label})
                      </Tag>
                    )
                  })}
              </div>
            </Descriptions.Item>
          </Descriptions>
        )}
      </Drawer>
    </div>
  )
}

// 简单的 SVG 力导向图组件
interface ForceGraphProps {
  nodes: GraphNode[]
  edges: GraphEdge[]
  onNodeClick: (nodeId: string) => void
}

const ForceGraph: React.FC<ForceGraphProps> = ({ nodes, edges, onNodeClick }) => {
  const containerRef = useRef<HTMLDivElement>(null)
  const [positions, setPositions] = useState<Record<string, { x: number; y: number }>>({})
  const [svgSize, setSvgSize] = useState({ width: 500, height: 400 })

  // ResizeObserver 让 SVG 自适应容器大小
  useEffect(() => {
    if (!containerRef.current) return
    const observer = new ResizeObserver(entries => {
      for (const entry of entries) {
        const { width, height } = entry.contentRect
        if (width > 0 && height > 0) {
          setSvgSize({ width: Math.floor(width), height: Math.floor(height) })
        }
      }
    })
    observer.observe(containerRef.current)
    return () => observer.disconnect()
  }, [])

  // 初始化力导向布局
  useEffect(() => {
    if (nodes.length === 0) return

    const graph = new Graph()

    // 添加节点
    for (const node of nodes) {
      graph.addNode(node.id, {
        label: node.label,
        x: Math.random() * 400 + 100,
        y: Math.random() * 300 + 100,
        size: 20,
        color: '#1890ff',
      })
    }

    // 添加边
    for (const edge of edges) {
      if (graph.hasNode(edge.source) && graph.hasNode(edge.target)) {
        try {
          graph.addEdge(edge.source, edge.target, {
            label: edge.label,
            size: edge.weight * 3 + 1,
            color: REL_TYPE_COLORS[edge.label] || '#999',
          })
        } catch {
          // 边已存在则跳过
        }
      }
    }

    // 运行 ForceAtlas2
    if (graph.order > 0) {
      try {
        forceAtlas2.assign(graph, {
          iterations: 100,
          settings: {
            gravity: 1,
            scalingRatio: 10,
            strongGravityMode: true,
          },
        })
      } catch (e) {
        console.warn('ForceAtlas2 布局失败，使用随机位置:', e)
      }
    }

    // 提取位置
    const pos: Record<string, { x: number; y: number }> = {}
    graph.forEachNode((nodeId, attrs) => {
      pos[nodeId] = { x: (attrs.x as number) || 0, y: (attrs.y as number) || 0 }
    })

    setPositions(pos)
  }, [nodes, edges])

  if (nodes.length === 0) return null

  // 计算 bounds
  const posValues = Object.values(positions)
  if (posValues.length === 0) return null

  const minX = Math.min(...posValues.map(p => p.x))
  const maxX = Math.max(...posValues.map(p => p.x))
  const minY = Math.min(...posValues.map(p => p.y))
  const maxY = Math.max(...posValues.map(p => p.y))
  const rangeX = maxX - minX || 1
  const rangeY = maxY - minY || 1

  const { width, height } = svgSize
  const padding = 40
  const scaleX = (width - 2 * padding) / rangeX
  const scaleY = (height - 2 * padding) / rangeY

  const getX = (x: number) => (x - minX) * scaleX + padding
  const getY = (y: number) => (y - minY) * scaleY + padding

  return (
    <div
      ref={containerRef}
      style={{ flex: 1, overflow: 'auto', background: '#fafafa' }}
    >
      <svg width={width} height={height} style={{ cursor: 'grab' }}>
        {/* 绘制边 */}
        {edges.map(edge => {
          const fromPos = positions[edge.source]
          const toPos = positions[edge.target]
          if (!fromPos || !toPos) return null

          const x1 = getX(fromPos.x)
          const y1 = getY(fromPos.y)
          const x2 = getX(toPos.x)
          const y2 = getY(toPos.y)

          // 计算边的中点（用于放置标签）
          const midX = (x1 + x2) / 2
          const midY = (y1 + y2) / 2

          return (
            <g key={edge.id}>
              <line
                x1={x1}
                y1={y1}
                x2={x2}
                y2={y2}
                stroke={REL_TYPE_COLORS[edge.label] || '#999'}
                strokeWidth={Math.max(edge.weight * 3 + 1, 1)}
                strokeOpacity={0.6}
              />
              <text
                x={midX}
                y={midY - 5}
                textAnchor="middle"
                fontSize={10}
                fill={REL_TYPE_COLORS[edge.label] || '#999'}
                style={{ pointerEvents: 'none' }}
              >
                {edge.label}
              </text>
            </g>
          )
        })}

        {/* 绘制节点 */}
        {nodes.map(node => {
          const pos = positions[node.id]
          if (!pos) return null

          const cx = getX(pos.x)
          const cy = getY(pos.y)

          return (
            <g
              key={node.id}
              style={{ cursor: 'pointer' }}
              onClick={() => onNodeClick(node.id)}
            >
              <circle
                cx={cx}
                cy={cy}
                r={16}
                fill="#1890ff"
                stroke="#fff"
                strokeWidth={2}
              />
              <text
                x={cx}
                y={cy + 4}
                textAnchor="middle"
                fontSize={11}
                fill="#fff"
                style={{ pointerEvents: 'none', fontWeight: 'bold' }}
              >
                {node.label.slice(0, 2)}
              </text>
              <text
                x={cx}
                y={cy - 22}
                textAnchor="middle"
                fontSize={11}
                fill="#333"
                style={{ pointerEvents: 'none' }}
              >
                {node.label}
              </text>
            </g>
          )
        })}
      </svg>

      {/* 图例 */}
      <div
        style={{
          padding: '8px 16px',
          fontSize: 11,
          color: '#666',
          borderTop: '1px solid #e8e8e8',
          display: 'flex',
          gap: 12,
          flexWrap: 'wrap',
        }}
      >
        {Object.entries(REL_TYPE_COLORS).map(([type, color]) => (
          <span key={type} style={{ display: 'flex', alignItems: 'center', gap: 4 }}>
            <span
              style={{
                display: 'inline-block',
                width: 16,
                height: 2,
                background: color,
              }}
            />
            {type}
          </span>
        ))}
      </div>
    </div>
  )
}

export default CharacterGraph

import { useEffect, useRef, useState, forwardRef, useImperativeHandle } from 'react'
import * as monaco from 'monaco-editor'
import { Spin } from 'antd'
import { loader } from '@monaco-editor/react'

// 配置 Monaco Editor 加载路径（使用国内镜像，避免被墙）
loader.config({
  paths: {
    vs: 'https://cdn.bootcdn.net/ajax/libs/monaco-editor/0.45.0/min/vs'
  }
})

export interface EditorHandle {
  getSelectedText: () => string
  getCursorPosition: () => { lineNumber: number; column: number }
  insertText: (text: string) => void
  replaceSelection: (text: string) => void
}

interface EditorProps {
  value: string
  onChange: (value: string | undefined) => void
  filePath?: string
}

const Editor = forwardRef<EditorHandle, EditorProps>(({ value, onChange, filePath }, ref) => {
  const editorRef = useRef<HTMLDivElement>(null)
  const monacoEditorRef = useRef<monaco.editor.IStandaloneCodeEditor | null>(null)
  const onChangeRef = useRef(onChange)
  onChangeRef.current = onChange
  const [loading, setLoading] = useState(true)

  // 暴露编辑器方法给父组件
  useImperativeHandle(ref, () => ({
    getSelectedText: () => {
      if (!monacoEditorRef.current) return ''
      const selection = monacoEditorRef.current.getSelection()
      if (!selection) return ''
      return monacoEditorRef.current.getModel()?.getValueInRange(selection) || ''
    },
    getCursorPosition: () => {
      if (!monacoEditorRef.current) return { lineNumber: 1, column: 1 }
      const pos = monacoEditorRef.current.getPosition()
      return pos || { lineNumber: 1, column: 1 }
    },
    insertText: (text: string) => {
      if (!monacoEditorRef.current) return
      const position = monacoEditorRef.current.getPosition()
      if (position) {
        const range = new monaco.Range(
          position.lineNumber,
          position.column,
          position.lineNumber,
          position.column
        )
        monacoEditorRef.current.executeEdits('', [
          { range, text }
        ])
      }
    },
    replaceSelection: (text: string) => {
      if (!monacoEditorRef.current) return
      const selection = monacoEditorRef.current.getSelection()
      if (!selection) return
      monacoEditorRef.current.executeEdits('', [
        { range: selection, text }
      ])
    },
  }))

  // 初始化编辑器
  useEffect(() => {
    if (!editorRef.current) return

    let isMounted = true
    let debounceTimer: ReturnType<typeof setTimeout> | null = null
    const initEditor = async () => {
      try {
        // 加载 Monaco Editor
        await loader.init()

        if (!isMounted || !editorRef.current) return

        // 创建编辑器实例
        const editor = monaco.editor.create(editorRef.current, {
          value,
          language: 'markdown',
          theme: 'vs-light',
          fontSize: 16,
          lineHeight: 1.8,
          lineNumbers: 'on',
          wordWrap: 'on',
          wrappingIndent: 'indent',
          automaticLayout: true,
          minimap: { enabled: false },
          scrollBeyondLastLine: false,
          tabSize: 2,
          insertSpaces: true,
          renderWhitespace: 'none',
          renderLineHighlight: 'line',
          scrollbar: {
            verticalScrollbarSize: 10,
            horizontalScrollbarSize: 10,
          },
        })

        // 监听内容变化（带防抖，避免每次按键都触发父组件重渲染）
        editor.onDidChangeModelContent(() => {
          if (debounceTimer) clearTimeout(debounceTimer)
          debounceTimer = setTimeout(() => {
            if (!isMounted || !monacoEditorRef.current) return
            const newValue = editor.getValue()
            onChangeRef.current(newValue)
          }, 300)
        })

        // 保存快捷键
        editor.addCommand(monaco.KeyMod.CtrlCmd | monaco.KeyCode.KeyS, () => {
          // 保存由 Workbench 处理
          const saveEvent = new KeyboardEvent('keydown', {
            key: 's',
            ctrlKey: true,
            bubbles: true
          })
          window.dispatchEvent(saveEvent)
        })

        monacoEditorRef.current = editor
        setLoading(false)
      } catch (error) {
        console.error('初始化编辑器失败:', error)
        setLoading(false)
      }
    }

    initEditor()

    return () => {
      isMounted = false
      if (debounceTimer) clearTimeout(debounceTimer)
      if (monacoEditorRef.current) {
        monacoEditorRef.current.dispose()
        monacoEditorRef.current = null
      }
    }
  }, [])

  // 当外部 value 变化时更新编辑器内容
  useEffect(() => {
    if (!monacoEditorRef.current) return

    const currentValue = monacoEditorRef.current.getValue()
    if (currentValue !== value) {
      // 使用 executeEdits 替代 setValue，保留 undo/redo 历史
      const model = monacoEditorRef.current.getModel()
      if (model) {
        monacoEditorRef.current.executeEdits('', [{
          range: model.getFullModelRange(),
          text: value,
        }])
      }
    }
  }, [value])

  // 根据文件类型切换语言模式
  useEffect(() => {
    if (!monacoEditorRef.current || !filePath) return

    const model = monacoEditorRef.current.getModel()
    if (!model) return

    if (filePath.endsWith('.md') || filePath.endsWith('.markdown')) {
      monaco.editor.setModelLanguage(model, 'markdown')
    } else if (filePath.endsWith('.yaml') || filePath.endsWith('.yml')) {
      monaco.editor.setModelLanguage(model, 'yaml')
    } else if (filePath.endsWith('.json')) {
      monaco.editor.setModelLanguage(model, 'json')
    }
  }, [filePath])

  if (loading) {
    return (
      <div style={{ height: '100%', display: 'flex', alignItems: 'center', justifyContent: 'center' }}>
        <Spin tip="加载编辑器中..." />
      </div>
    )
  }

  return (
    <div ref={editorRef} style={{ width: '100%', height: '100%' }} />
  )
})

export default Editor

/**
 * 导出管理器
 * 支持 Markdown 和 EPUB 格式导出
 */

const pathJoin = (...parts: string[]) => parts.filter(Boolean).join('/')

import { useState } from 'react'
import {
  Button,
  Space,
  Modal,
  Form,
  Select,
  Switch,
  message,
  Progress,
  Alert,
  Radio,
  Divider,
  List,
  Card,
  Tag,
  Input,
} from 'antd'
import {
  DownloadOutlined,
  FileMarkdownOutlined,
  BookOutlined,
  CheckCircleOutlined,
  FolderOpenOutlined,
} from '@ant-design/icons'

interface ExportManagerProps {
  projectRoot: string | null
  projectName?: string
  visible: boolean
  onClose: () => void
}

interface ChapterInfo {
  path: string
  name: string
  volume: string
  order: number
  content?: string
}

interface ExportProgress {
  current: number
  total: number
  status: 'idle' | 'exporting' | 'done' | 'error'
  message: string
}

const ExportManager: React.FC<ExportManagerProps> = ({
  projectRoot,
  projectName = '小说',
  visible,
  onClose,
}) => {
  const [exportFormat, setExportFormat] = useState<'markdown' | 'epub'>('markdown')
  const [exportMode, setExportMode] = useState<'single' | 'byVolume'>('single')
  const [includeToc, setIncludeToc] = useState(true)
  const [progress, setProgress] = useState<ExportProgress>({
    current: 0,
    total: 0,
    status: 'idle',
    message: '',
  })
  const [exportPath, setExportPath] = useState<string | null>(null)

  // 加载所有章节
  const loadChapters = async (): Promise<ChapterInfo[]> => {
    if (!projectRoot) return []

    const chapters: ChapterInfo[] = []

    const readDir = async (dirPath: string, volumeName: string = '正文') => {
      try {
        const entriesResult = await window.electronAPI.readdir(dirPath)
        if (!entriesResult.success) { console.warn('读取目录失败:', dirPath, entriesResult.error); return; }
        const entries = entriesResult.data || []
        for (const entry of entries) {
          const fullPath = `${dirPath}/${entry.name}`
          if (entry.isDirectory) {
            await readDir(fullPath, entry.name)
          } else if (entry.isFile && entry.name.endsWith('.md') && !entry.name.startsWith('_')) {
            const contentResult = await window.electronAPI.readFile(fullPath)
            if (contentResult.success && contentResult.content) {
              // 提取章节序号
              const orderMatch = entry.name.match(/第(\d+)章/)
              chapters.push({
                path: fullPath,
                name: entry.name.replace('.md', ''),
                volume: volumeName,
                order: orderMatch ? parseInt(orderMatch[1]) : 0,
                content: contentResult.content,
              })
            }
          }
        }
      } catch (e) {
        console.warn('读取目录失败:', dirPath, e)
      }
    }

    const plotsDir = `${projectRoot}/plots`
    const existsResult = await window.electronAPI.exists(plotsDir)
    if (existsResult?.success && existsResult?.exists) {
      await readDir(plotsDir)
    }

    return chapters.sort((a, b) => {
      if (a.volume !== b.volume) return a.volume.localeCompare(b.volume)
      return a.order - b.order
    })
  }

  // 导出 Markdown
  const exportMarkdown = async () => {
    if (!projectRoot) return

    setProgress({ current: 0, total: 0, status: 'exporting', message: '加载章节...' })

    try {
      const chapters = await loadChapters()
      if (chapters.length === 0) {
        message.warning('没有找到可导出的章节')
        setProgress({ current: 0, total: 0, status: 'error', message: '没有找到章节' })
        return
      }

      // 读取 project.yaml 获取标题
      let title = projectName
      try {
        const projectResult = await window.electronAPI.yaml.read(`${projectRoot}/project.yaml`)
        if (projectResult.success && projectResult.data) {
          const data = projectResult.data as Record<string, unknown>
          if (data.title) title = String(data.title)
        }
      } catch {}

      setProgress({ current: 0, total: chapters.length, status: 'exporting', message: '正在导出...' })

      if (exportMode === 'single') {
        // 单文件导出
        let toc = ''
        if (includeToc) {
          toc = `# ${title}\n\n`
          toc += `> 导出时间：${new Date().toLocaleString()}\n\n`
          toc += `## 目录\n\n`
          const volumes = [...new Set(chapters.map(c => c.volume))]
          for (const vol of volumes) {
            toc += `### ${vol}\n\n`
            const volChapters = chapters.filter(c => c.volume === vol)
            for (const ch of volChapters) {
              toc += `- [${ch.name}](#${ch.name.replace(/\s/g, '-')})\n`
            }
            toc += '\n'
          }
          toc += '---\n\n'
        }

        let fullContent = toc

        // 按卷分组
        const volumes = [...new Set(chapters.map(c => c.volume))]
        for (const vol of volumes) {
          fullContent += `\n\n# ${vol}\n\n`
          const volChapters = chapters.filter(c => c.volume === vol)

          for (let i = 0; i < volChapters.length; i++) {
            const ch = volChapters[i]
            setProgress({
              current: i + 1,
              total: chapters.length,
              status: 'exporting',
              message: `正在处理: ${ch.name}`,
            })

            fullContent += `\n\n## ${ch.name}\n\n`
            fullContent += ch.content || ''
          }
        }

        // 选择导出位置
        const dirResult = await window.electronAPI.openDirectory()
        if (!dirResult.success || !dirResult.data) { message.info('已取消导出'); setProgress({ current: 0, total: 0, status: 'idle', message: '' }); return }

        const exportFile = pathJoin(dirResult.data!, `${title}.md`)
        try {
          const writeResult = await window.electronAPI.writeFile(exportFile, fullContent)
          if (!writeResult.success) throw new Error(writeResult.error || '写入失败')
          setExportPath(exportFile)
          setProgress({ current: chapters.length, total: chapters.length, status: 'done', message: '导出完成' })
          message.success(`已导出到: ${exportFile}`)
        } catch (err) {
          message.error(`导出失败: ${(err as Error).message}`)
          setProgress({ current: 0, total: 0, status: 'error', message: '导出失败' })
        }
      } else {
        // 按卷拆分导出
        const dirResult = await window.electronAPI.openDirectory()
        if (!dirResult.success || !dirResult.data) { message.info('已取消导出'); setProgress({ current: 0, total: 0, status: 'idle', message: '' }); return }

        const volumes = [...new Set(chapters.map(c => c.volume))]
        for (let vi = 0; vi < volumes.length; vi++) {
          const vol = volumes[vi]
          const volChapters = chapters.filter(c => c.volume === vol)

          let volContent = `# ${vol}\n\n`
          if (includeToc) {
            volContent += `## 目录\n\n`
            for (const ch of volChapters) {
              volContent += `- [${ch.name}](#${ch.name.replace(/\s/g, '-')})\n`
            }
            volContent += '\n---\n\n'
          }

          for (let ci = 0; ci < volChapters.length; ci++) {
            const ch = volChapters[ci]
            setProgress({
              current: vi * volChapters.length + ci + 1,
              total: chapters.length,
              status: 'exporting',
              message: `正在处理: ${vol}/${ch.name}`,
            })

            volContent += `\n\n## ${ch.name}\n\n`
            volContent += ch.content || ''
          }

          const exportFile = `${dirResult.data!}/${vol}.md`
          const volWriteResult = await window.electronAPI.writeFile(exportFile, volContent)
          if (!volWriteResult.success) {
            message.error(`写入失败: ${volWriteResult.error}`)
            setProgress({ current: 0, total: 0, status: 'error', message: '导出失败' })
            return
          }
        }

        setExportPath(dirResult.data!)
        setProgress({ current: chapters.length, total: chapters.length, status: 'done', message: '导出完成' })
        message.success(`已导出 ${volumes.length} 个文件到: ${dirResult.data}`)
      }
    } catch (error) {
      message.error('导出失败')
      setProgress({ current: 0, total: 0, status: 'error', message: '导出失败' })
    }
  }

  // 简单 HTML 转义
  const escapeHtml = (str: string): string => {
    return str
      .replace(/&/g, '&amp;')
      .replace(/</g, '&lt;')
      .replace(/>/g, '&gt;')
      .replace(/"/g, '&quot;')
      .replace(/'/g, '&#39;')
  }

  // 转换为 EPUB XHTML
  const markdownToXhtml = (md: string, chapterTitle: string): string => {
    // 简单转换：处理标题和段落
    let html = md
      .replace(/^### (.+)$/gm, '<h3>$1</h3>')
      .replace(/^## (.+)$/gm, '<h2>$1</h2>')
      .replace(/^# (.+)$/gm, '<h1>$1</h1>')
      .replace(/\n\n/g, '</p><p>')
      .replace(/\n/g, '<br/>')

    return `<?xml version="1.0" encoding="UTF-8"?>
<html xmlns="http://www.w3.org/1999/xhtml">
<head>
  <title>${escapeHtml(chapterTitle)}</title>
  <style>
    body { font-family: "SimSun", serif; font-size: 1em; line-height: 1.6; margin: 1em; }
    h1, h2, h3 { text-align: center; margin: 1em 0; }
    p { text-indent: 2em; margin: 0.5em 0; }
  </style>
</head>
<body>
  <h1>${escapeHtml(chapterTitle)}</h1>
  <p>${html}</p>
</body>
</html>`
  }

  // 生成 EPUB
  const exportEpub = async () => {
    if (!projectRoot) return

    setProgress({ current: 0, total: 0, status: 'exporting', message: '加载章节...' })

    try {
      const chapters = await loadChapters()
      if (chapters.length === 0) {
        message.warning('没有找到可导出的章节')
        setProgress({ current: 0, total: 0, status: 'error', message: '没有找到章节' })
        return
      }

      // 读取 project.yaml
      let title = projectName
      let author = '未知作者'
      try {
        const projectResult = await window.electronAPI.yaml.read(`${projectRoot}/project.yaml`)
        if (projectResult.success && projectResult.data) {
          const data = projectResult.data as Record<string, unknown>
          if (data.title) title = String(data.title)
          if (data.author) author = String(data.author)
        }
      } catch {}

      // 选择导出位置
      const epubDirResult = await window.electronAPI.openDirectory()
      if (!epubDirResult.success || !epubDirResult.data) { message.info('已取消导出'); setProgress({ current: 0, total: 0, status: 'idle', message: '' }); return }

      const safeTitle = title.replace(/[^\w\u4e00-\u9fa5]/g, '_')
      const epubDir = `${epubDirResult.data!}/${safeTitle}_epub`
      const metaResult = await window.electronAPI.mkdir(`${epubDir}/META-INF`)
      if (!metaResult.success) { throw new Error(metaResult.error || '创建META-INF失败') }
      const chaptersResult = await window.electronAPI.mkdir(`${epubDir}/OEBPS/chapters`)
      if (!chaptersResult.success) { throw new Error(chaptersResult.error || '创建OEBPS/chapters失败') }

      // mimetype（不压缩）
      const mtResult = await window.electronAPI.writeFile(`${epubDir}/mimetype`, 'application/epub+zip')
      if (!mtResult.success) throw new Error(`写入mimetype失败: ${mtResult.error}`)

      // container.xml
      const container = `<?xml version="1.0" encoding="UTF-8"?>
<container version="1.0" xmlns="urn:oasis:names:tc:opendocument:xmlns:container">
  <rootfiles>
    <rootfile full-path="OEBPS/content.opf" media-type="application/oebps-package+xml"/>
  </rootfiles>
</container>`
      const ctResult = await window.electronAPI.writeFile(`${epubDir}/META-INF/container.xml`, container)
      if (!ctResult.success) throw new Error(`写入container.xml失败: ${ctResult.error}`)

      // 生成 content.opf
      let spineItems = ''
      let manifestItems = ''
      for (let i = 0; i < chapters.length; i++) {
        const ch = chapters[i]
        const chFileName = `chapter_${String(i + 1).padStart(3, '0')}.xhtml`
        manifestItems += `    <item id="ch${i + 1}" href="chapters/${chFileName}" media-type="application/xhtml+xml"/>\n`
        spineItems += `    <itemref idref="ch${i + 1}"/>\n`
      }

      const contentOpf = `<?xml version="1.0" encoding="UTF-8"?>
<package xmlns="http://www.idpf.org/2007/opf" unique-identifier="BookId" version="2.0">
  <metadata xmlns:dc="http://purl.org/dc/elements/1.1/">
    <dc:title>${escapeHtml(title)}</dc:title>
    <dc:creator>${escapeHtml(author)}</dc:creator>
    <dc:language>zh-CN</dc:language>
    <dc:identifier id="BookId">urn:uuid:${Date.now()}</dc:identifier>
  </metadata>
  <manifest>
    ${manifestItems}
    <item id="ncx" href="toc.ncx" media-type="application/x-dtbncx+xml"/>
    <item id="toc" href="toc.xhtml" media-type="application/xhtml+xml"/>
  </manifest>
  <spine toc="ncx">
${spineItems}
  </spine>
</package>`
      const opfResult = await window.electronAPI.writeFile(`${epubDir}/OEBPS/content.opf`, contentOpf)
      if (!opfResult.success) throw new Error(`写入content.opf失败: ${opfResult.error}`)

      // 生成 toc.ncx
      let navPoints = ''
      for (let i = 0; i < chapters.length; i++) {
        const ch = chapters[i]
        const chFileName = `chapter_${String(i + 1).padStart(3, '0')}.xhtml`
        navPoints += `    <navPoint id="navpoint-${i + 1}" playOrder="${i + 1}">
      <navLabel><text>${escapeHtml(ch.name)}</text></navLabel>
      <content src="chapters/${chFileName}"/>
    </navPoint>\n`
      }

      const tocNcx = `<?xml version="1.0" encoding="UTF-8"?>
<ncx xmlns="http://www.dgipart.org/2007/ncx" version="2005-1">
  <head>
    <meta name="dtb:uid" content="urn:uuid:${Date.now()}"/>
    <meta name="dtb:depth" content="1"/>
    <meta name="dtb:totalPageCount" content="0"/>
    <meta name="dtb:maxPageNumber" content="0"/>
  </head>
  <docTitle><text>${escapeHtml(title)}</text></docTitle>
  <navMap>
${navPoints}
  </navMap>
</ncx>`
      const ncxResult = await window.electronAPI.writeFile(`${epubDir}/OEBPS/toc.ncx`, tocNcx)
      if (!ncxResult.success) throw new Error(`写入toc.ncx失败: ${ncxResult.error}`)

      // 生成章节内容
      for (let i = 0; i < chapters.length; i++) {
        const ch = chapters[i]
        setProgress({
          current: i + 1,
          total: chapters.length,
          status: 'exporting',
          message: `正在处理: ${ch.name}`,
        })

        const chFileName = `chapter_${String(i + 1).padStart(3, '0')}.xhtml`
        const xhtmlContent = markdownToXhtml(ch.content || '', ch.name)
        const chResult = await window.electronAPI.writeFile(`${epubDir}/OEBPS/chapters/${chFileName}`, xhtmlContent)
        if (!chResult.success) throw new Error(`写入章节失败: ${chResult.error}`)
      }

      // 生成 toc.xhtml (HTML目录)
      let tocHtml = `<?xml version="1.0" encoding="UTF-8"?>
<html xmlns="http://www.w3.org/1999/xhtml">
<head><title>目录</title></head>
<body>
<h1>目录</h1>
<nav xmlns="http://www.w3.org/1999/xhtml"><ol>`
      for (let i = 0; i < chapters.length; i++) {
        const ch = chapters[i]
        const chFileName = `chapter_${String(i + 1).padStart(3, '0')}.xhtml`
        tocHtml += `<li><a href="chapters/${chFileName}">${escapeHtml(ch.name)}</a></li>`
      }
      tocHtml += '</ol></nav></body></html>'
      const txResult = await window.electronAPI.writeFile(`${epubDir}/OEBPS/toc.xhtml`, tocHtml)
      if (!txResult.success) throw new Error(`写入toc.xhtml失败: ${txResult.error}`)

      setExportPath(epubDir)
      setProgress({ current: chapters.length, total: chapters.length, status: 'done', message: 'EPUB结构已生成' })
      message.success(`EPUB 文件结构已生成到: ${epubDir}\n请使用 epub 生成工具打包为 .epub 文件`)
    } catch (error) {
      message.error('EPUB 导出失败')
      setProgress({ current: 0, total: 0, status: 'error', message: '导出失败' })
    }
  }

  // 执行导出
  const handleExport = async () => {
    if (!projectRoot) {
      message.warning('请先打开项目')
      return
    }

    if (exportFormat === 'markdown') {
      await exportMarkdown()
    } else {
      await exportEpub()
    }
  }

  const handleOpenExport = async () => {
    if (exportPath) {
      const result = await window.electronAPI.openPath(exportPath)
      if (!result.success) {
        message.error(`打开失败: ${result.error}`)
      }
    }
  }

  return (
    <Modal
      title="📦 导出小说"
      open={visible}
      onCancel={onClose}
      width={500}
      footer={null}
      bodyStyle={{ maxHeight: '70vh', overflow: 'auto' }}
    >
      <div>
        <Alert
          message="导出功能可以将您的章节内容导出为标准格式，便于在其他平台发布"
          type="info"
          showIcon
          style={{ marginBottom: 16 }}
        />

        <Form layout="vertical">
          <Form.Item label="导出格式">
            <Radio.Group
              value={exportFormat}
              onChange={(e) => setExportFormat(e.target.value)}
            >
              <Radio.Button value="markdown">
                <FileMarkdownOutlined /> Markdown
              </Radio.Button>
              <Radio.Button value="epub">
                <BookOutlined /> EPUB
              </Radio.Button>
            </Radio.Group>
          </Form.Item>

          <Form.Item label="导出模式">
            <Radio.Group
              value={exportMode}
              onChange={(e) => setExportMode(e.target.value)}
            >
              <Radio value="single">单文件</Radio>
              <Radio value="byVolume">按卷拆分</Radio>
            </Radio.Group>
          </Form.Item>

          <Form.Item label="目录">
            <Switch checked={includeToc} onChange={setIncludeToc} />
            <span style={{ marginLeft: 8, color: '#666', fontSize: 12 }}>
              {includeToc ? '包含目录' : '不包含目录'}
            </span>
          </Form.Item>

          <Divider />

          {progress.status === 'exporting' && (
            <div style={{ marginBottom: 16 }}>
              <Progress
                percent={progress.total > 0 ? Math.round((progress.current / progress.total) * 100) : 0}
                status="active"
                format={(percent) => `${progress.current}/${progress.total}`}
              />
              <div style={{ fontSize: 12, color: '#666', textAlign: 'center' }}>
                {progress.message}
              </div>
            </div>
          )}

          {progress.status === 'done' && (
            <Alert
              message="导出完成！"
              description={exportPath}
              type="success"
              showIcon
              style={{ marginBottom: 16 }}
              action={
                <Button size="small" icon={<FolderOpenOutlined />} onClick={handleOpenExport}>
                  打开
                </Button>
              }
            />
          )}

          <Space>
            <Button
              type="primary"
              icon={<DownloadOutlined />}
              onClick={handleExport}
              loading={progress.status === 'exporting'}
              disabled={!projectRoot}
            >
              开始导出
            </Button>
            <Button onClick={onClose}>
              关闭
            </Button>
          </Space>
        </Form>
      </div>
    </Modal>
  )
}

export default ExportManager

/**
 * 事实台账面板
 * 支持按类型/角色/章节筛选，伏笔状态管理，点击跳转章节
 * 新增伏笔看板视图
 */

import { useState, useEffect, useCallback, useMemo, useRef } from 'react'
import {
  List,
  Tag,
  Tabs,
  Empty,
  Spin,
  Button,
  message,
  Select,
  Input,
  Card,
  Badge,
  Space,
  Tooltip,
  Modal,
  Form,
  InputNumber,
  Switch,
  Alert,
  Row,
  Col,
  Checkbox,
} from 'antd'
import {
  ThunderboltOutlined,
  FireOutlined,
  GiftOutlined,
  TeamOutlined,
  BulbOutlined,
  ReloadOutlined,
  SearchOutlined,
  FilterOutlined,
  EyeOutlined,
  CheckOutlined,
  ExclamationCircleOutlined,
  DragOutlined,
} from '@ant-design/icons'
import factsStore, { Fact } from '../db'
import factExtractor from '../services/factExtractor'

const { TabPane } = Tabs

type FactType = 'all' | 'power' | 'item' | 'relation' | 'foreshadow'

const typeLabels: Record<FactType, { label: string; icon: React.ReactNode; color: string }> = {
  all: { label: '全部', icon: <ThunderboltOutlined />, color: 'default' },
  power: { label: '战力', icon: <FireOutlined />, color: 'red' },
  item: { label: '物品', icon: <GiftOutlined />, color: 'gold' },
  relation: { label: '关系', icon: <TeamOutlined />, color: 'blue' },
  foreshadow: { label: '伏笔', icon: <BulbOutlined />, color: 'purple' },
}

type ForeshadowStatus = '铺设中' | '待回收' | '已回收'

interface ForeshadowItem {
  id: string
  description: string
  setupChapter: number
  payoffChapter?: number
  status: ForeshadowStatus
  relatedCharacters: string[]
  type: '剧情伏笔' | '人物伏笔' | '世界观伏笔'
  isOverdue?: boolean // 超过10章未回收
}

interface FactsPanelProps {
  projectRoot?: string | null
  onCharacterClick?: (name: string) => void
}

const FactsPanel: React.FC<FactsPanelProps> = ({ projectRoot, onCharacterClick }) => {
  const [activeTab, setActiveTab] = useState<FactType | 'kanban'>('all')
  const [facts, setFacts] = useState<Fact[]>([])
  const [allFacts, setAllFacts] = useState<Fact[]>([])
  const [loading, setLoading] = useState(false)
  const [searchText, setSearchText] = useState('')
  const [filterCharacter, setFilterCharacter] = useState<string>('')
  const [filterChapter, setFilterChapter] = useState<number | undefined>(undefined)
  const [showFilters, setShowFilters] = useState(false)
  const [characters, setCharacters] = useState<string[]>([])
  const [currentChapter, setCurrentChapter] = useState<number>(1)

  // 伏笔看板数据
  const [foreshadowItems, setForeshadowItems] = useState<ForeshadowItem[]>([])
  const [showAddForeshadow, setShowAddForeshadow] = useState(false)
  // 批量选择
  const [selectedIds, setSelectedIds] = useState<Set<string>>(new Set())
  // 拖拽排序
  const [draggingId, setDraggingId] = useState<string | null>(null)
  const [dragOverId, setDragOverId] = useState<string | null>(null)
  const [form] = Form.useForm()
  const mountedRef = useRef(true)

  // 组件卸载保护
  useEffect(() => {
    mountedRef.current = true
    return () => { mountedRef.current = false }
  }, [])

  // 加载事实
  const loadFacts = useCallback(async () => {
    if (!mountedRef.current) return
    setLoading(true)
    try {
      const result = await factsStore.getFacts(undefined, projectRoot)
      if (!mountedRef.current) return
      setAllFacts(result)

      // 提取所有角色名
      const charNames = Array.from(
        new Set(result.map(f => f.subject).filter(Boolean))
      ).sort() as string[]
      setCharacters(charNames)

      applyFilters(result)

      // 加载伏笔看板
      if (projectRoot && mountedRef.current) {
        setTimeout(() => loadForeshadowKanban(result), 0)
      }
    } catch (error) {
      if (!mountedRef.current) return
      message.error('加载事实失败')
      console.error(error)
    } finally {
      if (mountedRef.current) setLoading(false)
    }
  }, [projectRoot])

  // 加载伏笔看板
  const loadForeshadowKanban = async (facts?: Fact[]) => {
    if (!projectRoot) return
    const allFactsData = facts || allFacts
    try {
      const plotFactsFile = `${projectRoot}/facts/plot_facts.yaml`
      const result = await window.electronAPI.yaml.read(plotFactsFile)
      if (result.success && result.data) {
        const plotData = result.data as Record<string, unknown>
        const foreshadowList = (plotData['伏笔清单'] as Array<Record<string, unknown>>) || []

        // 获取当前最大章节数（用于判断超期）
        const chapters = allFactsData
          .map((f: Fact) => Math.max(f.chapterStart, f.chapterEnd))
          .filter((c: number) => c < 9999)
        const currentMaxChapter = chapters.length > 0 ? Math.max(...chapters) : currentChapter

        const items: ForeshadowItem[] = foreshadowList.map((fb, idx) => {
          const setupChapter = Number(fb['setup_chapter'] || 1)
          const payoffChapter = fb['payoff_chapter'] ? Number(fb['payoff_chapter']) : undefined
          const status = (fb['status'] as ForeshadowStatus) || '待回收'
          const isOverdue = !!(status !== '已回收' && !payoffChapter && currentMaxChapter >= setupChapter && (currentMaxChapter - setupChapter) > 10)

          return {
            id: String(fb['id'] || `fs-${idx}`),
            description: String(fb['description'] || ''),
            setupChapter,
            payoffChapter,
            status,
            relatedCharacters: (fb['related_characters'] as string[]) || [],
            type: (fb['type'] as ForeshadowItem['type']) || '剧情伏笔',
            isOverdue,
          }
        })

        setForeshadowItems(items)
      }
    } catch (error) {
      console.warn('加载伏笔看板失败:', error)
    }
  }

  // 获取当前最大章节数
  const getCurrentMaxChapter = (): number => {
    // 从 facts 中获取最大的章节号
    const chapters = allFacts
      .map(f => Math.max(f.chapterStart, f.chapterEnd))
      .filter(c => c < 9999)
    return chapters.length > 0 ? Math.max(...chapters) : currentChapter
  }

  // 更新伏笔状态
  const handleUpdateForeshadowStatus = async (
    item: ForeshadowItem,
    newStatus: ForeshadowStatus
  ) => {
    if (!projectRoot) return
    try {
      const plotFactsFile = `${projectRoot}/facts/plot_facts.yaml`
      const result = await window.electronAPI.yaml.read(plotFactsFile)
      if (result.success && result.data) {
        const plotData = result.data as Record<string, unknown>
        const foreshadowList = (plotData['伏笔清单'] as Array<Record<string, unknown>>) || []
        const updated = foreshadowList.map(fb => {
          if (fb['id'] === item.id) {
            return { ...fb, status: newStatus }
          }
          return fb
        })
        plotData['伏笔清单'] = updated
        const writeResult = await window.electronAPI.yaml.write(plotFactsFile, plotData)
        if (!writeResult.success) {
          message.error(`保存失败: ${writeResult.error}`)
          return
        }
        message.success(`伏笔状态已更新为「${newStatus}」`)
        await loadForeshadowKanban()
      }
    } catch (error) {
      message.error('更新失败')
    }
  }

  // 批量更新伏笔状态
  const handleBatchUpdateStatus = async (newStatus: ForeshadowStatus) => {
    if (!projectRoot || selectedIds.size === 0) return
    try {
      const plotFactsFile = `${projectRoot}/facts/plot_facts.yaml`
      const result = await window.electronAPI.yaml.read(plotFactsFile)
      if (result.success && result.data) {
        const plotData = result.data as Record<string, unknown>
        const foreshadowList = (plotData['伏笔清单'] as Array<Record<string, unknown>>) || []
        const updated = foreshadowList.map(fb => {
          if (selectedIds.has(String(fb['id']))) {
            return { ...fb, status: newStatus }
          }
          return fb
        })
        plotData['伏笔清单'] = updated
        const writeResult = await window.electronAPI.yaml.write(plotFactsFile, plotData)
        if (!writeResult.success) {
          message.error(`批量保存失败: ${writeResult.error}`)
          return
        }
        message.success(`已批量更新 ${selectedIds.size} 个伏笔为「${newStatus}」`)
        setSelectedIds(new Set())
        await loadForeshadowKanban()
      }
    } catch (error) {
      message.error('批量更新失败')
    }
  }

  // 添加伏笔
  const handleAddForeshadow = async () => {
    if (!projectRoot) return
    try {
      const values = await form.validateFields()
      const plotFactsFile = `${projectRoot}/facts/plot_facts.yaml`
      const result = await window.electronAPI.yaml.read(plotFactsFile)
      if (result.success && result.data) {
        const plotData = result.data as Record<string, unknown>
        const foreshadowList = (plotData['伏笔清单'] as Array<Record<string, unknown>>) || []

        foreshadowList.push({
          id: `FS${Date.now()}-${Math.random().toString(36).slice(2, 6)}`,
          description: values.description,
          setup_chapter: values.setupChapter || 1,
          payoff_chapter: values.payoffChapter || undefined,
          status: '铺设中',
          related_characters: values.relatedCharacters || [],
          type: values.type || '剧情伏笔',
        })

        plotData['伏笔清单'] = foreshadowList
        const writeResult = await window.electronAPI.yaml.write(plotFactsFile, plotData)
        if (!writeResult.success) {
          message.error(`保存失败: ${writeResult.error}`)
          return
        }
        message.success('伏笔已添加')
        setShowAddForeshadow(false)
        form.resetFields()
        await loadForeshadowKanban()
      }
    } catch (error) {
      message.error('添加失败')
    }
  }

  // 删除伏笔
  const handleDeleteForeshadow = async (item: ForeshadowItem) => {
    if (!projectRoot) return
    Modal.confirm({
      title: '确认删除此伏笔？',
      content: item.description,
      okText: '确认删除',
      okType: 'danger',
      onOk: async () => {
        try {
          const plotFactsFile = `${projectRoot}/facts/plot_facts.yaml`
          const result = await window.electronAPI.yaml.read(plotFactsFile)
          if (result.success && result.data) {
            const plotData = result.data as Record<string, unknown>
            const foreshadowList = (plotData['伏笔清单'] as Array<Record<string, unknown>>) || []
            const filtered = foreshadowList.filter(fb => fb['id'] !== item.id)
            plotData['伏笔清单'] = filtered
            const writeResult = await window.electronAPI.yaml.write(plotFactsFile, plotData)
            if (!writeResult.success) {
              message.error(`保存失败: ${writeResult.error}`)
              return
            }
            message.success('伏笔已删除')
            await loadForeshadowKanban()
          }
        } catch (error) {
          message.error('删除失败')
        }
      },
    })
  }

  // 提取当前章节事实
  const extractCurrentChapter = async () => {
    message.info('请在编辑器中选择章节后，使用右侧「AI工具 → 提取事实」功能')
  }

  // 应用筛选
  const applyFilters = useCallback((source: Fact[]) => {
    let filtered = source

    if (activeTab !== 'all') {
      filtered = filtered.filter(f => f.type === activeTab)
    }

    if (searchText) {
      const search = searchText.toLowerCase()
      filtered = filtered.filter(
        f =>
          f.subject.toLowerCase().includes(search) ||
          f.object?.toLowerCase().includes(search) ||
          f.content.toLowerCase().includes(search)
      )
    }

    if (filterCharacter) {
      filtered = filtered.filter(
        f => f.subject === filterCharacter || f.object === filterCharacter
      )
    }

    if (filterChapter) {
      filtered = filtered.filter(
        f => f.chapterStart <= filterChapter! && f.chapterEnd >= filterChapter!
      )
    }

    setFacts(filtered)
  }, [activeTab, searchText, filterCharacter, filterChapter])

  // 标签切换时重新筛选
  useEffect(() => {
    if (activeTab !== 'kanban') {
      applyFilters(allFacts)
    }
  }, [activeTab, searchText, filterCharacter, filterChapter, allFacts, applyFilters])

  // 切换标签时重新加载
  useEffect(() => {
    loadFacts()
  }, [projectRoot, loadFacts])

  // 格式化事实项
  const renderFactItem = (item: Fact) => {
    const typeInfo = typeLabels[item.type as FactType]
    const isForeshadow = item.type === 'foreshadow'

    return (
      <List.Item
        key={item.id}
        style={{ cursor: 'pointer' }}
      >
        <List.Item.Meta
          title={
            <div style={{ display: 'flex', alignItems: 'center', gap: 8, flexWrap: 'wrap' }}>
              <Tag color={typeInfo.color}>
                {typeInfo.icon} {typeInfo.label}
              </Tag>
              <strong>{item.subject}</strong>
              {item.object && (
                <>
                  <span style={{ color: '#999' }}>→</span>
                  <strong>{item.object}</strong>
                </>
              )}
              {isForeshadow && (
                <Tag
                  color={
                    item.content.includes('已回收')
                      ? 'green'
                      : item.content.includes('铺设中')
                        ? 'blue'
                        : 'orange'
                  }
                  style={{ marginLeft: 4 }}
                >
                  {item.content.includes('已回收') ? '已回收' : item.content.includes('铺设中') ? '铺设中' : '待回收'}
                </Tag>
              )}
            </div>
          }
          description={
            <div>
              <p style={{ margin: '4px 0' }}>{item.content}</p>
              <div
                style={{
                  fontSize: 12,
                  color: '#999',
                  marginTop: 4,
                  display: 'flex',
                  justifyContent: 'space-between',
                  alignItems: 'center',
                }}
              >
                <span>
                  第 {item.chapterStart} 章
                  {item.chapterEnd !== item.chapterStart && ` - 第 ${item.chapterEnd} 章`}
                </span>
              </div>
            </div>
          }
        />
      </List.Item>
    )
  }

  // 伏笔看板卡片
  const renderForeshadowCard = (item: ForeshadowItem) => {
    const isOverdue = item.isOverdue
    const isSelected = selectedIds.has(item.id)

    return (
      <div
        draggable
        onDragStart={() => setDraggingId(item.id)}
        onDragEnd={() => { setDraggingId(null); setDragOverId(null) }}
        onDragOver={(e) => { e.preventDefault(); setDragOverId(item.id) }}
        onDrop={(e) => {
          e.preventDefault()
          if (!draggingId || draggingId === item.id) return
          // 同一列内交换顺序
          setForeshadowItems(prev => {
            const arr = [...prev]
            const fromIdx = arr.findIndex(x => x.id === draggingId)
            const toIdx = arr.findIndex(x => x.id === item.id)
            if (fromIdx < 0 || toIdx < 0) return prev
            ;[arr[fromIdx], arr[toIdx]] = [arr[toIdx], arr[fromIdx]]
            return arr
          })
          setDraggingId(null)
          setDragOverId(null)
        }}
        style={{
          opacity: draggingId === item.id ? 0.4 : 1,
          border: dragOverId === item.id ? '2px dashed #1890ff' : undefined,
          borderRadius: 6,
        }}
      >
        <Card
          size="small"
          style={{
            marginBottom: 8,
            borderColor: isOverdue ? '#ff4d4f' : undefined,
            borderWidth: isOverdue ? 2 : 1,
            background: isSelected ? '#e6f7ff' : undefined,
          }}
          bodyStyle={{ padding: 10 }}
        >
          <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start' }}>
            <Checkbox
              checked={isSelected}
              onChange={(e) => {
                setSelectedIds(prev => {
                  const next = new Set(prev)
                  if (e.target.checked) next.add(item.id)
                  else next.delete(item.id)
                  return next
                })
              }}
              style={{ marginRight: 6, marginTop: 2 }}
            />
            <div style={{ flex: 1 }}>
              {isOverdue && (
                <Tag color="red" icon={<ExclamationCircleOutlined />} style={{ marginBottom: 4 }}>
                  超期未回收
                </Tag>
              )}
              <div style={{ fontSize: 13, marginBottom: 6 }}>{item.description}</div>
              <div style={{ fontSize: 11, color: '#999' }}>
                <span>铺设：第{item.setupChapter}章</span>
                {item.payoffChapter && (
                  <span> → 回收：第{item.payoffChapter}章</span>
                )}
              </div>
              {item.relatedCharacters.length > 0 && (
                <div style={{ marginTop: 4 }}>
                  {item.relatedCharacters.slice(0, 3).map(char => (
                    <Tag
                      key={char}
                      color="blue"
                      style={{ fontSize: 10, cursor: 'pointer' }}
                      onClick={() => onCharacterClick?.(char)}
                    >
                      {char}
                    </Tag>
                  ))}
                  {item.relatedCharacters.length > 3 && (
                    <Tag style={{ fontSize: 10 }}>+{item.relatedCharacters.length - 3}</Tag>
                  )}
                </div>
              )}
            </div>
            <Button
              type="text"
              size="small"
              danger
              icon={<CheckOutlined />}
              onClick={(e) => {
                e.stopPropagation()
                handleDeleteForeshadow(item)
              }}
              style={{ marginLeft: 4 }}
            />
          </div>
        </Card>
      </div>
    )
  }

  // 伏笔看板三列
  const renderForeshadowKanban = () => {
    const columns: { status: ForeshadowStatus; color: string; items: ForeshadowItem[] }[] = [
      { status: '铺设中', color: 'blue', items: foreshadowItems.filter(f => f.status === '铺设中') },
      { status: '待回收', color: 'orange', items: foreshadowItems.filter(f => f.status === '待回收') },
      { status: '已回收', color: 'green', items: foreshadowItems.filter(f => f.status === '已回收') },
    ]

    const overdueCount = foreshadowItems.filter(f => f.isOverdue).length

    return (
      <div style={{ height: '100%', display: 'flex', flexDirection: 'column' }}>
        <div style={{ padding: '8px 16px', borderBottom: '1px solid #e8e8e8' }}>
          <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: 8 }}>
            <Space>
              <span style={{ fontWeight: 500 }}>伏笔看板</span>
              <Badge count={foreshadowItems.length} style={{ fontSize: 10 }} />
            </Space>
            <Button
              size="small"
              type="primary"
              icon={<BulbOutlined />}
              onClick={() => setShowAddForeshadow(true)}
            >
              添加伏笔
            </Button>
          </div>
          {overdueCount > 0 && (
            <Alert
              message={`有 ${overdueCount} 个伏笔超过10章未回收（已标红）`}
              type="warning"
              showIcon
              style={{ fontSize: 11, marginBottom: 8 }}
            />
          )}
          {selectedIds.size > 0 && (
            <div style={{ marginBottom: 8, padding: '4px 8px', background: '#e6f7ff', borderRadius: 4, display: 'flex', gap: 8, alignItems: 'center' }}>
              <span style={{ fontSize: 12 }}>已选 {selectedIds.size} 个</span>
              <Button size="small" onClick={() => handleBatchUpdateStatus('待回收')}>标记待回收</Button>
              <Button size="small" type="primary" onClick={() => handleBatchUpdateStatus('已回收')}>标记已回收</Button>
              <Button size="small" onClick={() => setSelectedIds(new Set())}>取消选择</Button>
            </div>
          )}
        </div>

        <div style={{ flex: 1, overflow: 'auto', padding: 12 }}>
          <Row gutter={8}>
            {columns.map(col => (
              <Col key={col.status} span={8}>
                <div
                  style={{
                    background: '#f5f5f5',
                    borderRadius: 8,
                    padding: 8,
                    minHeight: 300,
                  }}
                >
                  <div style={{
                    display: 'flex',
                    justifyContent: 'space-between',
                    alignItems: 'center',
                    marginBottom: 8,
                    fontWeight: 500,
                    color: col.color,
                  }}>
                    <Checkbox
                      checked={col.items.length > 0 && col.items.every(item => selectedIds.has(item.id))}
                      indeterminate={col.items.some(item => selectedIds.has(item.id)) && !col.items.every(item => selectedIds.has(item.id))}
                      onChange={(e) => {
                        setSelectedIds(prev => {
                          const next = new Set(prev)
                          if (e.target.checked) col.items.forEach(item => next.add(item.id))
                          else col.items.forEach(item => next.delete(item.id))
                          return next
                        })
                      }}
                    />
                    <span>{col.status}</span>
                    <Badge
                      count={col.items.length}
                      style={{ marginLeft: 6 }}
                      color={col.color}
                    />
                  </div>

                  {col.items.length === 0 ? (
                    <div style={{ textAlign: 'center', color: '#999', padding: 20, fontSize: 12 }}>
                      暂无伏笔
                    </div>
                  ) : (
                    <div>
                      {col.items.map(item => renderForeshadowCard(item))}
                    </div>
                  )}
                </div>
              </Col>
            ))}
          </Row>
        </div>

        {/* 添加伏笔 Modal */}
        <Modal
          title="添加伏笔"
          open={showAddForeshadow}
          onCancel={() => setShowAddForeshadow(false)}
          onOk={handleAddForeshadow}
          okText="添加"
        >
          <Form form={form} layout="vertical">
            <Form.Item
              name="description"
              label="伏笔描述"
              rules={[{ required: true, message: '请输入伏笔描述' }]}
            >
              <Input.TextArea rows={2} placeholder="描述这个伏笔的内容..." />
            </Form.Item>
            <Form.Item name="setupChapter" label="铺设章节" initialValue={1}>
              <InputNumber min={1} style={{ width: '100%' }} />
            </Form.Item>
            <Form.Item name="payoffChapter" label="计划回收章节">
              <InputNumber min={1} placeholder="留空表示未计划" style={{ width: '100%' }} />
            </Form.Item>
            <Form.Item name="type" label="伏笔类型" initialValue="剧情伏笔">
              <Select
                options={[
                  { value: '剧情伏笔', label: '剧情伏笔' },
                  { value: '人物伏笔', label: '人物伏笔' },
                  { value: '世界观伏笔', label: '世界观伏笔' },
                ]}
              />
            </Form.Item>
            <Form.Item name="relatedCharacters" label="关联角色">
              <Select
                mode="tags"
                placeholder="输入角色名（回车确认）"
                options={characters.map(c => ({ value: c, label: c }))}
              />
            </Form.Item>
          </Form>
        </Modal>
      </div>
    )
  }

  // 统计摘要
  const stats = useMemo(() => ({
    total: allFacts.length,
    power: allFacts.filter(f => f.type === 'power').length,
    item: allFacts.filter(f => f.type === 'item').length,
    relation: allFacts.filter(f => f.type === 'relation').length,
    foreshadow: foreshadowItems.length,
    foreshadowPending: foreshadowItems.filter(f => f.status === '待回收').length,
    foreshadowOverdue: foreshadowItems.filter(f => f.isOverdue).length,
  }), [allFacts, foreshadowItems])

  return (
    <div style={{ height: '100%', display: 'flex', flexDirection: 'column' }}>
      {/* 头部 */}
      <div style={{ padding: '10px 16px', borderBottom: '1px solid #e8e8e8' }}>
        {/* 统计栏 */}
        <div
          style={{
            display: 'flex',
            gap: 8,
            marginBottom: 10,
            flexWrap: 'wrap',
            fontSize: 12,
          }}
        >
          <Badge count={stats.total} showZero color="#1890ff" style={{ fontSize: 11 }}>
            <span style={{ padding: '2px 8px', background: '#f0f0f0', borderRadius: 4 }}>全部</span>
          </Badge>
          <Badge count={stats.power} showZero color="#ff4d4f" style={{ fontSize: 11 }}>
            <span style={{ padding: '2px 8px', background: '#f0f0f0', borderRadius: 4 }}>战力</span>
          </Badge>
          <Badge count={stats.relation} showZero color="#1677ff" style={{ fontSize: 11 }}>
            <span style={{ padding: '2px 8px', background: '#f0f0f0', borderRadius: 4 }}>关系</span>
          </Badge>
          <Badge count={stats.foreshadow} showZero color="#722ed1" style={{ fontSize: 11 }}>
            <span style={{ padding: '2px 8px', background: '#f0f0f0', borderRadius: 4 }}>
              伏笔
              {stats.foreshadowPending > 0 && ` (${stats.foreshadowPending}待收)`}
            </span>
          </Badge>
          {stats.foreshadowOverdue > 0 && (
            <Badge count={stats.foreshadowOverdue} showZero color="#ff4d4f" style={{ fontSize: 11 }}>
              <span style={{ padding: '2px 8px', background: '#fff1f0', borderRadius: 4, color: '#ff4d4f' }}>
                超期
              </span>
            </Badge>
          )}
        </div>

        {/* 搜索和筛选 */}
        <div style={{ display: 'flex', gap: 8, alignItems: 'center', marginBottom: 10 }}>
          <Input
            placeholder="搜索事实..."
            prefix={<SearchOutlined />}
            value={searchText}
            onChange={(e) => setSearchText(e.target.value)}
            allowClear
            size="small"
            style={{ flex: 1 }}
          />
          <Button
            size="small"
            icon={<FilterOutlined />}
            onClick={() => setShowFilters(!showFilters)}
            type={showFilters ? 'primary' : 'default'}
          >
            筛选
          </Button>
          <Button
            size="small"
            icon={<ReloadOutlined />}
            onClick={loadFacts}
          />
        </div>

        {/* 高级筛选 */}
        {showFilters && (
          <div style={{ marginBottom: 10, padding: 8, background: '#f5f5f5', borderRadius: 6 }}>
            <Space direction="vertical" style={{ width: '100%' }}>
              <Select
                placeholder="按角色筛选"
                value={filterCharacter || undefined}
                onChange={(val) => setFilterCharacter(val || '')}
                options={characters.map(c => ({ value: c, label: c }))}
                style={{ width: '100%' }}
                size="small"
                allowClear
                showSearch
              />
              <InputNumber
                placeholder="按章节筛选"
                value={filterChapter}
                onChange={(val) => setFilterChapter(val ?? undefined)}
                min={1}
                style={{ width: '100%' }}
                size="small"
              />
              <Button
                size="small"
                onClick={() => {
                  setFilterCharacter('')
                  setFilterChapter(undefined)
                }}
              >
                清除筛选
              </Button>
            </Space>
          </div>
        )}

        <Tabs
          activeKey={activeTab}
          onChange={(key) => setActiveTab(key as FactType | 'kanban')}
          size="small"
        >
          {Object.entries(typeLabels).map(([key, info]) => (
            <TabPane
              key={key}
              tab={<span>{info.icon} {info.label}</span>}
            />
          ))}
          <TabPane key="kanban" tab={<span><BulbOutlined /> 伏笔看板</span>} />
        </Tabs>
      </div>

      {/* 列表 / 看板 */}
      <div style={{ flex: 1, overflow: 'auto', padding: '0 16px' }}>
        {activeTab === 'kanban' ? (
          renderForeshadowKanban()
        ) : loading ? (
          <div style={{ padding: 40, textAlign: 'center' }}>
            <Spin tip="加载中..." />
          </div>
        ) : facts.length === 0 ? (
          <div style={{ padding: 40, textAlign: 'center' }}>
            <Empty
              description="暂无事实记录"
              image={Empty.PRESENTED_IMAGE_SIMPLE}
            />
          </div>
        ) : (
          <List
            dataSource={facts}
            renderItem={renderFactItem}
            size="small"
            style={{ padding: '10px 0' }}
          />
        )}
      </div>
    </div>
  )
}

export default FactsPanel

import { useState, useEffect } from 'react'
import { Tree, Spin, Empty, message } from 'antd'
import { FileOutlined, FolderOutlined } from '@ant-design/icons'
import type { DataNode } from 'antd/es/tree'

// 浏览器环境下替代 path.join 的工具函数
const pathJoin = (...parts: string[]): string => {
  return parts.filter(Boolean).join('/')
}

interface OutlineTreeProps {
  projectRoot: string
  activeChapter: string | null
  onSelect: (filePath: string) => void
}

interface FileEntry {
  name: string
  isDirectory: boolean
  isFile: boolean
  path: string
  children?: FileEntry[]
}

const OutlineTree = ({ projectRoot, activeChapter, onSelect }: OutlineTreeProps) => {
  const [treeData, setTreeData] = useState<DataNode[]>([])
  const [loading, setLoading] = useState(false)
  const [expandedKeys, setExpandedKeys] = useState<React.Key[]>([])

  // 读取目录结构
  const loadDirectory = async (dirPath: string): Promise<FileEntry[]> => {
    try {
      const entries = await window.electronAPI.readdir(dirPath)
      if (!entries || !entries.success || !Array.isArray(entries.data)) {
        console.error('[OutlineTree] readdir failed or returned non-array:', entries, 'dirPath:', dirPath)
        return []
      }

      const result: FileEntry[] = []

      for (const entry of entries.data) {
        const fullPath = pathJoin(dirPath, entry.name)

        if (entry.isDirectory) {
          const children = await loadDirectory(fullPath)
          result.push({
            name: entry.name,
            isDirectory: true,
            isFile: false,
            path: fullPath,
            children
          })
        } else if (entry.isFile && entry.name.endsWith('.md')) {
          result.push({
            name: entry.name.replace('.md', ''),
            isDirectory: false,
            isFile: true,
            path: fullPath
          })
        }
      }

      return result.sort((a, b) => {
        if (a.isDirectory && !b.isDirectory) return -1
        if (!a.isDirectory && b.isDirectory) return 1
        return a.name.localeCompare(b.name)
      })
    } catch (error) {
      console.error('读取目录失败:', error)
      return []
    }
  }

  // 转换为 Ant Design Tree 需要的格式
  const convertToTreeData = (entries: FileEntry[], parentKey: string = ''): DataNode[] => {
    return entries.map((entry, index) => {
      const key = entry.path  // 统一用真实路径作为 key，保证选中高亮正确

      if (entry.isDirectory && entry.children) {
        return {
          title: entry.name,
          key,
          icon: <FolderOutlined />,
          children: convertToTreeData(entry.children, key),
          isLeaf: false
        }
      } else {
        return {
          title: entry.name,
          key,
          icon: <FileOutlined />,
          isLeaf: true
        }
      }
    })
  }

  // 加载大纲
  useEffect(() => {
    const loadOutline = async () => {
      if (!projectRoot) return

      setLoading(true)
      try {
        const plotsDir = pathJoin(projectRoot, 'plots')
        const existsResult = await window.electronAPI.exists(plotsDir)
        if (!existsResult || !existsResult.success || !existsResult.exists) {
          const mkdirResult = await window.electronAPI.mkdir(plotsDir)
          if (!mkdirResult || !mkdirResult.success) {
            message.error(`创建 plots 目录失败: ${mkdirResult?.error || '未知错误'}`)
            console.error('[OutlineTree] mkdir failed:', mkdirResult, 'plotsDir:', plotsDir)
          }
          setTreeData([])
          return
        }

        const entries = await loadDirectory(plotsDir)
        const data = convertToTreeData(entries)
        setTreeData(data)

        const getAllKeys = (nodes: DataNode[]): string[] => {
          let keys: string[] = []
          nodes.forEach(node => {
            keys.push(node.key as string)
            if (node.children) keys = keys.concat(getAllKeys(node.children))
          })
          return keys
        }
        setExpandedKeys(getAllKeys(data))
      } catch (error: any) {
        message.error('加载大纲失败')
        const plotsDirHint = projectRoot ? pathJoin(projectRoot, 'plots') : 'unknown'
        console.error('[OutlineTree] loadOutline error:', error?.message || error, 'plotsDir:', plotsDirHint)
      } finally {
        setLoading(false)
      }
    }

    loadOutline()
  }, [projectRoot])

  // 监听文件变化，自动刷新大纲
  useEffect(() => {
    if (!projectRoot) return

    const plotsDir = pathJoin(projectRoot, 'plots')
    window.electronAPI.fsWatch(plotsDir)

    const removeListener = window.electronAPI.onFsChange(() => {
      loadDirectory(pathJoin(projectRoot, 'plots')).then(entries => {
        const data = convertToTreeData(entries)
        setTreeData(data)
      })
    })

    return () => {
      removeListener()
      window.electronAPI.fsUnwatch()
    }
  }, [projectRoot])

  // 处理选择
  const handleSelect = (selectedKeys: React.Key[]) => {
    if (selectedKeys.length === 0) return
    const key = String(selectedKeys[0])
    if (key.startsWith('/') || key.includes('.md')) {
      onSelect(key)
    }
  }

  if (loading) {
    return (
      <div style={{ padding: 20, textAlign: 'center' }}>
        <Spin tip="加载中..." />
      </div>
    )
  }

  if (treeData.length === 0) {
    return (
      <div style={{ padding: 20 }}>
        <Empty
          description="暂无章节"
          image={Empty.PRESENTED_IMAGE_SIMPLE}
        />
      </div>
    )
  }

  return (
    <div style={{ height: '100%', overflow: 'auto', padding: 10 }}>
      <Tree
        treeData={treeData}
        expandedKeys={expandedKeys}
        selectedKeys={activeChapter ? [activeChapter] : []}
        onSelect={handleSelect}
        onExpand={setExpandedKeys}
        showIcon
        defaultExpandAll
      />
    </div>
  )
}

